export const faqs: FAQItem[] = [
  // === TITLE & OWNERSHIP (basics) ===
  { q: "What is title?", a: "Title is your legal right to own, use, and dispose of your property. It establishes your ownership interest and any limitations on that ownership — such as easements, liens, or deed restrictions. When you buy a home, you receive title through a deed that's recorded with your county.", cat: "basics" },
  { q: "What is a title search?", a: "A title search is a thorough examination of public records — deeds, mortgages, court records, tax records, and other documents — going back decades to verify a clear chain of ownership. Title professionals trace every transfer of ownership, looking for outstanding liens, judgments, easements, or other issues that could affect your rights. According to ALTA, approximately 1 in 3 title searches reveals an issue that must be resolved before closing.", cat: "basics" },
  { q: "What is a deed and how is it different from a title?", a: "A deed is the physical legal document that transfers property ownership from one party to another — it's what gets signed at closing and recorded with the county. Title is the concept of ownership itself — your legal right to the property. Think of the deed as the vehicle that delivers title. Types include: warranty deed (strongest — seller guarantees clear title), special warranty deed (seller warrants only during their ownership), and quitclaim deed (no warranties — transfers whatever interest the grantor has).", cat: "basics", source: "CFPB: What Happens at Closing?", sourceUrl: "https://www.consumerfinance.gov/ask-cfpb/what-is-a-mortgage-closing-what-happens-at-the-closing-en-176/" },
  { q: "What is a chain of title?", a: "The chain of title is the complete history of ownership transfers for a property, from the original land patent (government grant) through every subsequent owner to the present day. Each link in the chain is a recorded deed or other transfer document. Any break, gap, or irregularity in the chain can create a title defect that clouds your ownership. This is one of the primary things the title search examines.", cat: "basics", source: "CFPB: Owning a Home Guide", sourceUrl: "https://www.consumerfinance.gov/owning-a-home/" },
  { q: "What is a lien?", a: "A lien is a legal claim against a property that serves as security for a debt. Common types include: mortgage liens (from your home loan), property tax liens (unpaid taxes), mechanic's liens (unpaid contractors), HOA liens (unpaid association dues), and judgment liens (court-ordered debts). Liens must typically be paid off or released before a property can be sold with clear title.", cat: "basics", source: "CFPB: Owning a Home Guide", sourceUrl: "https://www.consumerfinance.gov/owning-a-home/" },
  { q: "What is an easement?", a: "An easement is the legal right for someone other than the property owner to use a portion of the property for a specific purpose. Common examples include utility easements (allowing power, water, or sewer companies to access their infrastructure), access easements (allowing a neighbor to use your driveway), and drainage easements. Easements 'run with the land' — they transfer to new owners automatically and typically cannot be removed.", cat: "basics", source: "CFPB: Owning a Home Guide", sourceUrl: "https://www.consumerfinance.gov/owning-a-home/" },
  { q: "What is an encumbrance?", a: "An encumbrance is any claim, lien, charge, or liability attached to a property that may affect its value or limit its use — but doesn't prevent the transfer of ownership. Encumbrances include mortgages, liens, easements, deed restrictions, and encroachments. They're identified during the title search and listed as exceptions on your title commitment.", cat: "basics", source: "CFPB: Owning a Home Guide", sourceUrl: "https://www.consumerfinance.gov/owning-a-home/" },
  { q: "What does ALTA do?", a: "The American Land Title Association (ALTA) is the national trade organization for the title insurance industry, representing 6,000+ member companies across all 50 states. Founded in 1907, ALTA develops industry best practices, advocates before Congress and federal agencies, provides professional education, and helps consumers understand title insurance. ALTA does NOT issue policies directly — that's done by member title companies and underwriters.", cat: "basics" },
  { q: "What is a cloud on title?", a: "A cloud on title is any irregularity, possible claim, or encumbrance that could impair the owner's title or make it unmarketable. Examples include an unreleased mortgage from a previous owner, a missing heir who might claim ownership, a forged deed in the chain of title, or an improperly recorded document. Clouds must be resolved ('cured') before title insurance can be issued. This curative work is one of the most valuable services title professionals provide.", cat: "basics", source: "CFPB: Owner's Title Insurance", sourceUrl: "https://www.consumerfinance.gov/ask-cfpb/what-is-owners-title-insurance-en-164/" },
  { q: "What is adverse possession?", a: "Adverse possession is a legal doctrine that allows someone who occupies land they don't own to eventually claim legal ownership — if they meet specific requirements for a period set by state law (typically 5-20 years). The possession must generally be open, notorious, continuous, exclusive, and hostile (without the owner's permission). Title insurance protects against claims of adverse possession.", cat: "basics", source: "Cornell Law: Adverse Possession", sourceUrl: "https://www.law.cornell.edu/wex/adverse_possession" },

  // === TITLE INSURANCE (insurance) ===
  { q: "What is title insurance?", a: "Title insurance is a policy that protects your investment and property rights against losses from defects in the title that existed before you purchased the property — even if those defects weren't discovered during the title search. Unlike other insurance that covers future events (fire, theft), title insurance protects against past events that haven't been discovered yet. It's a one-time premium paid at closing for lifetime coverage.", cat: "insurance", source: "CFPB: What Is Owner's Title Insurance?", sourceUrl: "https://www.consumerfinance.gov/ask-cfpb/what-is-owners-title-insurance-en-164/" },
  { q: "Why should I purchase owner's title insurance?", a: "Owner's title insurance provides permanent protection for your property investment against future legal claims regarding ownership. For a one-time fee at closing (typically 0.5-1% of the purchase price), you and your heirs receive coverage for as long as you own the home. The policy covers legal defense costs (which can exceed $50,000 even for baseless claims) and pays covered losses up to your policy amount. Without it, you'd personally bear these costs.", cat: "insurance" },
  { q: "What's the difference between an owner's policy and a lender's policy?", a: "A lender's policy protects only the mortgage lender's investment — it does NOT protect you as the homeowner. It covers the declining loan balance, not your equity. An owner's policy protects YOUR equity and ownership rights for as long as you own the property. Most lenders require a lender's policy as a mortgage condition, but the owner's policy is optional (and strongly recommended). Purchasing both simultaneously typically qualifies for a significant discount.", cat: "insurance", source: "CFPB: Owner's vs Lender's Title Insurance", sourceUrl: "https://www.consumerfinance.gov/ask-cfpb/what-is-owners-title-insurance-en-164/" },
  { q: "What does owner's title insurance cover?", a: "The ALTA Owner's Policy covers specific risks including: someone else claiming ownership of your property; forged or fraudulently executed documents in the chain of title; documents signed by minors or incapacitated persons; improperly recorded documents; unknown liens or encumbrances; restrictions that were violated by a previous owner; lack of legal access to the property; and unmarketable title that prevents you from selling. The policy also covers your legal defense costs for covered claims.", cat: "insurance", source: "CFPB: What Is Owner's Title Insurance?", sourceUrl: "https://www.consumerfinance.gov/ask-cfpb/what-is-owners-title-insurance-en-164/" },
  { q: "What does owner's title insurance NOT cover?", a: "Title insurance does not cover: defects, liens, or encumbrances created by you after the policy date; government regulations (zoning, building codes) unless they cause a loss of title; defects that you agreed to or knew about; environmental contamination; matters that would be revealed by a physical survey (unless survey coverage is added); and items specifically listed as exceptions in Schedule B of your policy. Always review Schedule B carefully.", cat: "insurance" },
  { q: "How much does title insurance cost?", a: "Owner's title insurance typically costs 0.5% to 1% of the purchase price — a one-time fee for lifetime coverage. For a $350,000 home, that's approximately $1,750 to $3,500. Rates are regulated by each state's department of insurance. In some states (like Texas), rates are set by the state and are uniform. In others, rates vary by company — which is why RESPA gives you the right to shop. Ask about simultaneous issue discounts when buying both owner's and lender's policies.", cat: "insurance", source: "CFPB: Title Insurance Disclosure Factsheet", sourceUrl: "https://files.consumerfinance.gov/f/documents/cfpb_tila-respa_title-insurance-disclosures-factsheet.pdf" },
  { q: "How long does title insurance coverage last?", a: "Your owner's title insurance policy lasts for as long as you or your heirs own the property. There are no annual premiums, no renewals, and no expiration date — you pay once at closing and you're covered for life. If you leave the property to your heirs, they inherit the coverage. The only way coverage ends is when you sell the property or transfer ownership.", cat: "insurance", source: "CFPB: Owner's Title Insurance", sourceUrl: "https://www.consumerfinance.gov/ask-cfpb/what-is-owners-title-insurance-en-164/" },
  { q: "Can I choose my own title company?", a: "Yes. Under the federal Real Estate Settlement Procedures Act (RESPA), you have the legal right to choose your own title insurance company. Your lender or real estate agent may recommend a provider, but you are NOT obligated to use them, and they cannot require you to use a specific company. Shopping around can save hundreds of dollars and help you find a company you trust. Look for ALTA members who follow Best Practices.", cat: "insurance", source: "CFPB: RESPA - Your Right to Shop", sourceUrl: "https://www.consumerfinance.gov/owning-a-home/" },
  { q: "How do I file a title insurance claim?", a: "Contact your title insurance company promptly when you discover any concern. Common triggers: someone claims ownership or an interest in your property, a lien appears that wasn't disclosed at closing, a boundary dispute arises, you discover a restrictive easement, or a buyer's title search reveals a defect when you try to sell. Provide: your property address, policy number (if available), description of the issue, and supporting documents. Your insurer investigates, provides legal defense if needed, and pays covered losses.", cat: "insurance", source: "CFPB: Owner's Title Insurance", sourceUrl: "https://www.consumerfinance.gov/ask-cfpb/what-is-owners-title-insurance-en-164/" },
  { q: "What is a title commitment?", a: "A title commitment (also called a preliminary title report) is the document your title company issues after completing the title search. It states the conditions under which the company is willing to insure your title. Schedule A shows the policy details (amount, property description, how title is vested). Schedule B lists exceptions — known issues NOT covered by the policy (easements, deed restrictions, etc.). Review Schedule B with your agent or attorney — some exceptions can be removed through curative work.", cat: "insurance", source: "CFPB: Owner's Title Insurance", sourceUrl: "https://www.consumerfinance.gov/ask-cfpb/what-is-owners-title-insurance-en-164/" },
  { q: "What is an endorsement?", a: "A title insurance endorsement is an addition or modification to your standard policy that expands or changes coverage. Common endorsements include: survey coverage (covers boundary disputes), zoning compliance, access rights, condominium coverage, and adjustable rate mortgage protection. Endorsements are available for an additional fee and must be requested. Ask your title company which endorsements are available and recommended for your property type and location.", cat: "insurance" },

  // === COSTS & FEES (costs) ===
  { q: "What are closing costs?", a: "Closing costs are the fees and expenses beyond the purchase price that you pay to complete your home purchase. They typically range from 2% to 5% of the home price. For a $350,000 home, expect $7,000-$17,500. Major categories: loan origination (0.5-1%), appraisal ($300-600), title search ($200-400), title insurance (0.5-1% owner's policy), settlement fee ($500-2,000), recording fees ($50-250), homeowner's insurance (first year), and prepaid property taxes.", cat: "costs", source: "CFPB: Understand Closing Costs", sourceUrl: "https://www.consumerfinance.gov/owning-a-home/close/understand-closing-costs/" },
  { q: "Can I negotiate closing costs?", a: "Yes, many closing costs are negotiable. Strategies include: comparing Loan Estimates from multiple lenders (required within 3 business days of application under CFPB rules); negotiating seller concessions (asking the seller to pay a portion — capped at 3-9% depending on loan type); shopping for title insurance (your right under RESPA); asking about lender credits (higher rate in exchange for lower fees); closing near month-end (reduces prepaid interest); and checking for first-time buyer programs in your state.", cat: "costs", source: "CFPB: Compare Closing Costs", sourceUrl: "https://www.consumerfinance.gov/owning-a-home/close/understand-closing-costs/" },
  { q: "What is PMI and how can I avoid it?", a: "Private Mortgage Insurance is required by most lenders when your down payment is less than 20%. PMI protects the lender (not you) if you default. It typically costs 0.5-1.5% of the loan annually, added to your monthly payment. Avoid it by: putting 20%+ down, choosing a VA loan (no PMI ever), or using a piggyback loan. PMI can be removed: by request at 20% equity, automatically at 22% equity under the Homeowners Protection Act, or by refinancing once you have sufficient equity.", cat: "costs", source: "CFPB: When Can I Remove PMI?", sourceUrl: "https://www.consumerfinance.gov/ask-cfpb/when-can-i-remove-private-mortgage-insurance-en-202/" },
  { q: "What is an escrow account?", a: "Escrow serves two purposes. During the transaction, an escrow account holds your earnest money safely with a neutral third party (usually the title company). After closing, your lender may set up a mortgage escrow account that collects a portion of your property taxes and homeowner's insurance with each monthly payment, then pays those bills when due. This ensures taxes and insurance stay current. Your initial escrow deposit at closing typically covers 2-6 months of taxes and insurance.", cat: "costs" },
  { q: "What is earnest money and do I get it back?", a: "Earnest money (1-3% of purchase price) is a deposit showing the seller you're serious. It's held in escrow by the title company. If the transaction closes, it's applied to your down payment/closing costs. If you back out for a reason covered by your contingencies (failed inspection, financing falls through, low appraisal), you typically get it back. If you back out for an uncovered reason, you may forfeit it to the seller. Know your contingency deadlines.", cat: "costs", source: "NAR: Earnest Money Refunds, Returns and Regulations", sourceUrl: "https://www.nar.realtor/magazine/real-estate-news/sales-marketing/earnest-money-in-real-estate-refunds-returns-and-regulations" },
  { q: "What is RESPA?", a: "The Real Estate Settlement Procedures Act is federal law protecting consumers during closing. Key protections: lenders must provide a Loan Estimate within 3 business days of application; you can choose your own title/settlement services; kickbacks between providers are prohibited; lenders can't require you to use a specific title company; you must receive a Closing Disclosure 3 days before closing; and your lender must provide an annual escrow analysis statement. Enforced by the CFPB. Source: CFPB", cat: "costs", source: "CFPB: RESPA Compliance Resources", sourceUrl: "https://www.consumerfinance.gov/compliance/compliance-resources/mortgage-resources/tila-respa-integrated-disclosures/" },
  { q: "Who pays for what at closing?", a: "It varies by state and is often negotiable. Buyers typically pay: loan origination, appraisal, home inspection, lender's title insurance, homeowner's insurance, prepaid taxes/interest, and PMI. Sellers typically pay: real estate commissions (now negotiated separately per the 2024 NAR settlement — no standard percentage), owner's title insurance (in some states), transfer taxes, and repair credits. Your purchase agreement specifies who pays each fee. In some markets, sellers offer to pay buyer closing costs as an incentive.", cat: "costs", source: "CFPB: Closing Costs Explained", sourceUrl: "https://www.consumerfinance.gov/owning-a-home/close/understand-closing-costs/" },
  { q: "What is a simultaneous issue discount?", a: "When you purchase both an owner's and lender's title insurance policy from the same company at the same time, many companies offer a reduced rate on the second policy. This can save $200-$500 or more. The discount is available because much of the work (title search, examination) is the same for both policies. Always ask about this discount — not all companies volunteer it.", cat: "costs", source: "CFPB: Title Insurance Disclosure", sourceUrl: "https://files.consumerfinance.gov/f/documents/cfpb_tila-respa_title-insurance-disclosures-factsheet.pdf" },
  { q: "What are prepaid costs?", a: "Prepaids are costs you pay at closing that cover future expenses, not closing-related fees. They include: prepaid interest (from closing date to end of month), first year's homeowner's insurance premium, initial property tax escrow deposit (typically 2-6 months), and initial insurance escrow deposit. Prepaids can add $3,000-$8,000+ to your cash needed at closing depending on when in the month you close and your tax/insurance amounts.", cat: "costs", source: "CFPB: Understand Closing Costs", sourceUrl: "https://www.consumerfinance.gov/owning-a-home/close/understand-closing-costs/" },

  // === CLOSING PROCESS (closing) ===
  { q: "What happens at closing?", a: "Closing (settlement) is the final step where ownership transfers. You'll sign 50-100+ pages including: Closing Disclosure, promissory note (promise to repay), deed of trust (security for the loan), deed (ownership transfer), and various affidavits. The closing agent explains each document. You provide certified funds or wire confirmation. After signing, funds are disbursed, the deed is recorded with the county, and you receive the keys. Closings typically take 30-90 minutes.", cat: "closing", source: "CFPB: What Is a Mortgage Closing?", sourceUrl: "https://www.consumerfinance.gov/ask-cfpb/what-is-a-mortgage-closing-what-happens-at-the-closing-en-176/" },
  { q: "What is the Closing Disclosure?", a: "A 5-page standardized form detailing the final terms of your mortgage and every cost you'll pay. Under the CFPB's TRID rule, your lender must deliver it at least 3 business days before closing. It shows: loan terms, projected payments, closing costs itemized, cash needed at closing, and a comparison to your Loan Estimate. If certain items change (APR increases >1/8%, prepayment penalty added, loan product changes), a new 3-day waiting period starts. Source: CFPB", cat: "closing", source: "CFPB: Closing Disclosure Explainer", sourceUrl: "https://www.consumerfinance.gov/owning-a-home/closing-disclosure/" },
  { q: "What is the Loan Estimate?", a: "A 3-page standardized form your lender must provide within 3 business days of your mortgage application. It shows: estimated interest rate, monthly payment, closing costs, and key loan features. Get Loan Estimates from at least 3 lenders and compare APRs (not just rates) — the APR includes fees and gives the true cost. Federal law limits how much fees can increase between the Loan Estimate and Closing Disclosure. Source: CFPB", cat: "closing", source: "CFPB: Loan Estimate Explainer", sourceUrl: "https://www.consumerfinance.gov/owning-a-home/loan-estimate/" },
  { q: "Can I close remotely?", a: "Four methods exist: in-person (traditional, at the settlement office), mail-away/mobile notary (documents sent to you, notary comes to your location), hybrid (most docs signed digitally, brief office visit for key papers), and Remote Online Notarization/RON (fully digital via live video). The majority of U.S. states now have RON legislation, but availability depends on your county recorder and lender. Ask your title company early. Source: ALTA", cat: "closing" },
  { q: "What is a final walk-through?", a: "The final walk-through is your last inspection of the property before closing — typically done the morning of or day before closing. You're verifying: the property is in the agreed-upon condition, all negotiated repairs were completed, no new damage occurred, all fixtures and appliances that were included in the sale are still there, and the seller has fully vacated. If you find issues, raise them BEFORE signing at closing — it's much harder to get remedies afterward.", cat: "closing", source: "CFPB: Mortgage Closing Checklist", sourceUrl: "https://files.consumerfinance.gov/f/documents/cfpb_buying-a-house_mortgage-closing_checklist.pdf" },
  { q: "What should I NOT do during the closing process?", a: "Once under contract, avoid: opening new credit cards, making large purchases on credit, changing jobs, making large unexplained cash deposits, co-signing on anyone else's loan, or closing existing credit accounts. Your lender pulls credit again before closing — any changes can delay or kill your loan approval. Even a small new debt can push your DTI past the threshold. Wait until after closing and funding to make changes.", cat: "closing", source: "CFPB: Before, During, and After Closing", sourceUrl: "https://www.consumerfinance.gov/ask-cfpb/what-should-i-do-before-during-and-after-the-mortgage-closing-process-en-1907/" },
  { q: "How long does closing take?", a: "The closing appointment itself typically takes 30-90 minutes. However, the entire process from accepted offer to closing usually takes 30-45 days for conventional loans, 45-60 days for FHA loans, and varies for VA and USDA loans. Delays are common — common causes include appraisal issues, title defects requiring resolution, lender underwriting conditions, missing documents, and changes in the buyer's financial situation.", cat: "closing", source: "CFPB: The Closing Process", sourceUrl: "https://www.consumerfinance.gov/owning-a-home/mortgage-closing/" },
  { q: "What is a dry closing vs. a wet closing?", a: "In a 'wet' closing (most common), funds are disbursed and the deed is recorded on the same day as signing. You get your keys at or shortly after the closing table. In a 'dry' closing, the documents are signed but funds are not immediately disbursed — there may be a 1-3 day delay before funds transfer and the deed records. Some states (like California, Oregon, Washington) commonly have dry closings. Ask your settlement agent which to expect.", cat: "closing", source: "CFPB: Mortgage Closing Guide", sourceUrl: "https://www.consumerfinance.gov/owning-a-home/mortgage-closing/" },

  // === FRAUD & SAFETY (fraud) ===
  { q: "What is wire fraud in real estate?", a: "Wire fraud occurs when criminals intercept or impersonate parties in a real estate transaction to redirect closing funds. They hack email accounts, send fake wiring instructions, and steal down payments — often hundreds of thousands of dollars. The FBI reported $275.1 million in real estate wire fraud losses in 2025, a 59% increase from the prior year. BEC (Business Email Compromise) attacks increased 1,760% since AI tools became available. Source: FBI IC3, CertifID 2026", cat: "fraud", source: "CertifID 2026 State of Wire Fraud Report", sourceUrl: "https://www.certifid.com/state-of-wire-fraud" },
  { q: "How do I verify wiring instructions are legitimate?", a: "ALWAYS call your title company using a phone number you already have on file — NEVER a number from a suspicious email. Legitimate companies: never send wire instructions solely by email, never pressure last-minute changes, use wire verification technology (CertifID, Closinglock), and will happily confirm details by phone. If anything seems unusual — stop and call. Recovery rates: ~20% within 1 hour, ~10% within 24 hours, <5% after 48 hours. Source: FBI IC3", cat: "fraud", source: "CertifID 2026 State of Wire Fraud Report", sourceUrl: "https://www.certifid.com/state-of-wire-fraud" },
  { q: "What should I do if I'm a victim of wire fraud?", a: "Act within MINUTES: (1) Contact your bank immediately, request a wire recall — every minute matters. (2) Call your title company using a known number. (3) File with FBI IC3 at ic3.gov. (4) File with FinCEN. (5) Contact local law enforcement. (6) Document everything — screenshot emails, save headers, note call times. The first hour is your best window for recovery. After 48 hours, recovery drops below 5%. Source: FBI IC3", cat: "fraud", source: "FBI Internet Crime Complaint Center", sourceUrl: "https://www.ic3.gov/" },
  { q: "What is a deepfake scam in real estate?", a: "Criminals use AI to create realistic fake audio, video, or images to impersonate real estate agents, title officers, or sellers. Deepfake scams in real estate increased 40% year-over-year according to the 2026 Entrust Identity Fraud Report. They may send AI-generated voice messages with 'updated' wire instructions or conduct fake video calls impersonating your closing agent. Always verify identity through a separate, trusted channel. Source: NAR, Entrust 2026", cat: "fraud", source: "NAR: Consumer Guide to Spotting Deepfake Scams", sourceUrl: "https://www.nar.realtor/the-facts/consumer-guide-spotting-deepfake-scams-in-real-estate" },
  { q: "What should my title company be doing to prevent fraud?", a: "Ask if they: use wire verification technology (CertifID, Closinglock), require multi-factor authentication on all accounts, send documents through encrypted portals (not plain email), conduct regular cybersecurity training, carry cyber insurance/E&O coverage, and have a documented verbal verification process for wire instructions. Companies following ALTA Best Practices Pillar 3 (Privacy and Data Security) should have these measures in place. Source: ALTA", cat: "fraud", source: "ALTA Best Practices Pillar 3", sourceUrl: "https://www.alta.org/best-practices/" },

  // === MORTGAGES & LOANS (mortgage) ===
  { q: "What's the difference between pre-qualification and pre-approval?", a: "Pre-qualification is an informal estimate based on information you provide verbally — it's not verified and carries little weight with sellers. Pre-approval is a formal process where the lender verifies your income, assets, debts, and credit, then issues a conditional commitment for a specific loan amount. Pre-approval shows sellers you're a serious, qualified buyer. Get pre-approved before house hunting and obtain Loan Estimates from at least 3 lenders.", cat: "mortgage" },
  { q: "What types of mortgages are available?", a: "Four main types: Conventional (backed by Fannie Mae/Freddie Mac, 3-20% down, best rates at 740+ credit), FHA (government-insured, 3.5% down with 580+ credit, MIP for life of loan if down payment is under 10%), VA (zero down for eligible military/veterans, no monthly MI, funding fee applies), and USDA (zero down for eligible rural areas, income limits apply, lowest MI). Each has different requirements for credit score, down payment, mortgage insurance, and DTI ratio. Source: FHA.com, VA.gov, USDA.gov, Fannie Mae", cat: "mortgage", source: "FHA.com / VA.gov / USDA.gov / Fannie Mae", sourceUrl: "https://www.consumerfinance.gov/owning-a-home/explore/decide-on-loan-term/" },
  { q: "What is DTI and why does it matter?", a: "Debt-to-Income ratio is your total monthly debt payments divided by your gross monthly income. Lenders use two DTI ratios: front-end (housing costs only, ideally ≤28%) and back-end (all debts, ideally ≤36%). Maximum DTI varies by loan type: Conventional (45%), FHA (43%), VA (41%), USDA (41%). A lower DTI means you're less risky to the lender and may qualify for better rates. Reduce DTI by paying down debts before applying.", cat: "mortgage", source: "CFPB: Determine How Much You Can Afford", sourceUrl: "https://www.consumerfinance.gov/owning-a-home/explore/decide-how-much/" },
  { q: "Should I get a fixed or adjustable rate mortgage?", a: "Fixed-rate: same rate and payment for the entire loan term. Predictable and stable. Best if you plan to stay long-term or rates are low. Adjustable-rate (ARM): lower initial rate that adjusts periodically (usually after 5, 7, or 10 years). The rate can increase or decrease based on market indexes. Best if you plan to move or refinance before the adjustment period. ARMs have caps limiting how much the rate can change per adjustment and over the life of the loan.", cat: "mortgage", source: "CFPB: Decide on Loan Term", sourceUrl: "https://www.consumerfinance.gov/owning-a-home/explore/decide-on-loan-term/" },
  { q: "What is a rate lock?", a: "A rate lock is a guarantee from your lender that your interest rate won't change for a specific period (typically 30-60 days). Once locked, your rate is protected even if market rates rise. If rates drop, you're generally stuck at your locked rate (though some lenders offer float-down options). Lock when you're comfortable with the rate and confident your closing will happen within the lock period. Lock extensions may cost extra.", cat: "mortgage", source: "CFPB: Explore Interest Rates", sourceUrl: "https://www.consumerfinance.gov/owning-a-home/explore-rates/" },
  { q: "What is the difference between interest rate and APR?", a: "The interest rate is the cost of borrowing the principal loan amount. The APR (Annual Percentage Rate) is the total cost of the loan including the interest rate PLUS lender fees, discount points, mortgage insurance, and other costs — expressed as a yearly rate. The APR is always equal to or higher than the interest rate. Use APR to compare loan offers from different lenders — it gives you the true cost of each option. Required on all Loan Estimates. Source: CFPB", cat: "mortgage", source: "CFPB: Know Before You Owe", sourceUrl: "https://www.consumerfinance.gov/know-before-you-owe/" },

  // === INSPECTIONS (inspection) ===
  { q: "Do I really need a home inspection?", a: "Yes — it's one of the most important investments in the homebuying process. A $300-500 inspection can reveal tens of thousands in hidden problems. According to ASHI, approximately 86% of inspections find issues. The inspector examines structure, roof, plumbing, electrical, HVAC, and interior. They work for YOU, not the seller. Never waive the inspection contingency in your purchase agreement — even in competitive markets. Source: ASHI", cat: "inspection", source: "American Society of Home Inspectors (ASHI)", sourceUrl: "https://www.homeinspector.org/" },
  { q: "What is a home appraisal?", a: "A professional assessment of a property's fair market value, ordered by your lender to verify the home is worth the loan amount. The appraiser evaluates condition, features, location, and comparable sales. If the appraisal comes in low, you can: negotiate a lower price, increase your down payment to cover the gap, challenge the appraisal with additional comps, or walk away (if you have an appraisal contingency). Cost: $300-600, paid by the buyer. Source: Appraisal Institute", cat: "inspection", source: "Appraisal Institute: Appraising a Home", sourceUrl: "https://www.appraisalinstitute.org/" },
  { q: "Who pays for the home inspection?", a: "The buyer pays for the home inspection in the vast majority of transactions — and that's a good thing. Because you're paying the inspector, they work for you and owe their loyalty to you, not the seller. Typical cost: $300-500 for a general inspection. Specialty inspections (radon, sewer scope, mold, termite) are additional. The investment is small compared to the potential cost of undiscovered problems.", cat: "inspection", source: "ASHI: Hiring an Inspector", sourceUrl: "https://www.homeinspector.org/" },
  { q: "What specialty inspections might I need?", a: "Based on the property and location: radon testing ($100-200, recommended everywhere — #2 cause of lung cancer), sewer scope ($150-300, strongly recommended for 20+ year homes), termite/pest ($75-150, required for some loans), mold testing ($200-600, if moisture issues found), well water ($100-500, required for private wells), septic ($250-500, required for septic systems), foundation assessment ($300-800, if significant cracks noted), and chimney ($150-500, if fireplace present). Source: ASHI, EPA, NPMA", cat: "inspection" },
  { q: "Should I get a new construction home inspected?", a: "Absolutely. Three inspections are recommended: (1) Pre-drywall inspection before walls are closed — you can see framing, plumbing, electrical, and HVAC. This is the most valuable. (2) Pre-closing inspection 1-2 weeks before final walk-through. (3) 11-month warranty inspection before the builder's 1-year warranty expires. Even new homes have defects — improper grading, HVAC errors, builder shortcuts. Cost: $300-400 per inspection. Source: InterNACHI", cat: "inspection", source: "InterNACHI: New Construction Inspections", sourceUrl: "https://www.nachi.org/" },

  // === DOCUMENTS (documents) ===
  { q: "What is the Closing Disclosure and when will I get it?", a: "A 5-page form with final mortgage terms and every cost. Your lender must deliver it at least 3 business days before closing (CFPB TRID rule). Compare EVERY line to your Loan Estimate. Some fees can't increase at all (zero tolerance: origination, transfer taxes), some can increase up to 10% in aggregate (title services, recording fees), and some have no limit (services you chose, prepaids). If zero-tolerance fees increased, your lender must refund the difference. Source: CFPB", cat: "documents" },
  { q: "What should I bring to closing?", a: "Required: government-issued photo ID (valid, not expired), certified/cashier's check or wire confirmation for closing costs, proof of homeowner's insurance (binder effective on/before closing date). Recommended: your Closing Disclosure (for reference), Loan Estimate (for comparison), purchase agreement, home inspection report, bank statements, and contact numbers for your lender, agent, and insurance company. Two forms of ID is safer. Arrive early.", cat: "documents" },
  { q: "What is a promissory note?", a: "Your legally binding promise to repay the mortgage loan. It specifies: the loan amount, interest rate, monthly payment amount, payment due dates, late payment penalties, and consequences of default. Unlike the deed of trust (which is recorded publicly), the promissory note is a private document between you and the lender. If you default, the note plus the deed of trust allow the lender to foreclose.", cat: "documents", source: "CFPB: What Is a Promissory Note?", sourceUrl: "https://www.consumerfinance.gov/ask-cfpb/what-is-a-promissory-note-en-2108/" },
  { q: "What is a deed of trust?", a: "Also called a security instrument or mortgage (depending on your state). It gives the lender a security interest in your property — meaning if you fail to make payments, the lender has the legal right to foreclose and sell the property to recover the loan balance. It's recorded with the county as a public record. When you pay off your mortgage, the lender records a release/reconveyance, removing their lien from your title.", cat: "documents", source: "CFPB: What Is a Deed of Trust?", sourceUrl: "https://www.consumerfinance.gov/ask-cfpb/what-is-a-deed-of-trust-en-2081/" },

  // === YOUR RIGHTS (rights) ===
  { q: "What rights do I have as a homebuyer?", a: "Key federal rights: choose your own title company and settlement services (RESPA); receive a Loan Estimate within 3 business days of application (TRID); receive your Closing Disclosure 3 days before closing (TRID); be free from discrimination in housing (Fair Housing Act); receive a copy of your appraisal before closing; cancel certain loans within 3 days (right of rescission for refinances); and file complaints with the CFPB. State laws may provide additional protections. Source: CFPB, HUD", cat: "rights" },
  { q: "Can my lender force me to use a specific title company?", a: "No. Under RESPA, your lender cannot require you to use a specific title insurance company. They can recommend one, but you have the legal right to choose your own. If you feel pressured, remind them of your RESPA rights or file a complaint with the CFPB. Shopping around can save you money and ensure you work with a company you trust. Look for ALTA members who follow Best Practices.", cat: "rights", source: "CFPB: RESPA FAQs", sourceUrl: "https://www.consumerfinance.gov/compliance/compliance-resources/mortgage-resources/real-estate-settlement-procedures-act/real-estate-settlement-procedures-act-faqs/" },
  { q: "What is the right of rescission?", a: "For mortgage refinances (not purchase loans), you have 3 business days after closing to cancel the transaction without penalty. This is your federal 'cooling off' period under the Truth in Lending Act (TILA). During this period, the lender cannot disburse funds. If you rescind, the lender must return any fees you paid within 20 days. This right does NOT apply to purchase mortgages — only refinances of your primary residence. Source: CFPB", cat: "rights", source: "CFPB: Right of Rescission", sourceUrl: "https://www.consumerfinance.gov/ask-cfpb/for-a-home-equity-loan-or-home-equity-line-of-credit-what-is-the-right-of-rescission-en-137/" },
  { q: "What if I find errors on my Closing Disclosure?", a: "Contact your lender AND settlement agent immediately — before closing if possible. If fees increased beyond TRID tolerance limits, your lender must cure (refund) the difference. Zero-tolerance fees (origination charges, transfer taxes) cannot increase at all. 10%-tolerance fees can increase up to 10% in aggregate. If you find errors at the closing table, you can ask to delay closing to correct them. Never sign documents you believe contain errors. Source: CFPB", cat: "rights", source: "CFPB: Questions About Closing", sourceUrl: "https://www.consumerfinance.gov/owning-a-home/mortgage-closing/" },

  // === AFTER CLOSING (after) ===
  { q: "What happens after I close?", a: "After signing, the settlement agent disburses funds and sends your deed to the county recorder's office for recording (typically same day or next business day). Recording makes your ownership official and public. Your final title insurance policy arrives by mail in 2-8 weeks. Your first mortgage payment is usually due 30-60 days after closing. Keep all closing documents in a safe, permanent location — you'll need them for taxes, insurance claims, and when you eventually sell.", cat: "after", source: "CFPB: After the Closing", sourceUrl: "https://www.consumerfinance.gov/ask-cfpb/what-should-i-do-before-during-and-after-the-mortgage-closing-process-en-1907/" },
  { q: "When will I receive my title insurance policy?", a: "Your final owner's title insurance policy typically arrives by mail 2-8 weeks after closing. This is different from the title commitment (which you received before closing). The policy is your permanent proof of coverage. Store it in a safe place — you'll need it if you ever file a claim or if someone challenges your ownership. If you don't receive it within 90 days, contact your title company.", cat: "after" },
  { q: "What if I lose my title insurance policy?", a: "Contact the title company or underwriter that issued the policy. They maintain records and can provide a duplicate. If you can't remember who issued it, check your closing documents, contact the settlement agent who handled your closing, or call your state's department of insurance for help locating the insurer. Our Find My Policy page has a directory of all 50 state insurance departments with phone numbers.", cat: "after" },
  { q: "Can my mortgage be sold to another company?", a: "Yes — and it's very common. Most mortgages are sold on the secondary market after closing. Your loan terms (rate, payment, balance) cannot change when the loan is transferred, but your payment address and servicer will change. Your new servicer must notify you at least 15 days before your first payment is due to them. If both the old and new servicers fail to notify you, you have a 60-day grace period with no late fees. Source: CFPB", cat: "after", source: "CFPB: What Happens When My Mortgage Is Sold", sourceUrl: "https://www.consumerfinance.gov/ask-cfpb/what-happens-when-my-mortgage-is-sold-en-175/" },
  { q: "How long should I keep my closing documents?", a: "Keep your closing documents for as long as you own the property — plus 3-7 years after you sell (for tax purposes). Key documents to keep permanently: deed, title insurance policy, survey, settlement statement/Closing Disclosure, and any amendments or modifications. Keep digitally and physically. You'll need them for: filing insurance claims, refinancing, resolving boundary disputes, calculating capital gains when selling, and verifying ownership.", cat: "after", source: "IRS: Recordkeeping for Homeowners", sourceUrl: "https://www.irs.gov/taxtopics/tc701" },

  // === MORE MORTGAGES & LOANS ===
  { q: "How many lenders should I compare?", a: "At least 3. Under CFPB rules, each lender must provide a Loan Estimate within 3 business days of your application. Compare APRs (not just rates), origination fees, and total closing costs. Multiple mortgage credit inquiries within a 14-45 day window count as a single inquiry on your credit report, so shopping doesn't hurt your score. Even a 0.25% rate difference saves thousands over 30 years.", cat: "mortgage", source: "CFPB: Shop for Your Mortgage", sourceUrl: "https://www.consumerfinance.gov/owning-a-home/shop/" },
  { q: "What is a conforming loan limit?", a: "The maximum loan amount that Fannie Mae and Freddie Mac will purchase. For 2025, the baseline conforming limit is $806,500 (higher in high-cost areas — up to $1,209,750 in the most expensive markets like San Francisco). Loans above this limit are called 'jumbo' loans and typically have stricter requirements and higher rates. FHA has its own lower limits that vary by county. Source: FHFA", cat: "mortgage", source: "FHFA: Conforming Loan Limit Values", sourceUrl: "https://www.fhfa.gov/data/conforming-loan-limit-values" },
  { q: "What is a jumbo loan?", a: "A mortgage that exceeds the conforming loan limit ($806,500 baseline in 2025). Jumbo loans aren't backed by Fannie Mae or Freddie Mac, so lenders take on more risk and typically require: higher credit scores (700-720+), larger down payments (10-20%+), more cash reserves, lower DTI ratios, and charge higher interest rates. Jumbo loans are common in high-cost markets like New York, San Francisco, and Los Angeles.", cat: "mortgage", source: "FHFA: Conforming Loan Limits", sourceUrl: "https://www.fhfa.gov/data/conforming-loan-limit-values" },
  { q: "What is a construction loan?", a: "A short-term loan that finances the building of a new home. Construction loans typically have higher interest rates, require larger down payments (20-25%), and disburse funds in stages ('draws') as construction milestones are completed. Most convert to a permanent mortgage after construction is done (construction-to-permanent loan) or require you to refinance into a traditional mortgage. Title insurance is still needed — it protects against liens filed by contractors.", cat: "mortgage" },
  { q: "Can I buy a home with student loan debt?", a: "Yes. Student loans affect your DTI ratio, but they don't disqualify you. Tips: FHA counts 1% of loan balance or actual payment (whichever is lower) for IBR/IDR plans. Conventional loans use the actual payment if documented. Pay down high-interest debts first to improve DTI. Consider income-driven repayment plans to lower monthly payments. Get pre-approved to see where you stand. Many first-time buyers successfully purchase with student debt.", cat: "mortgage", source: "CFPB: Dealing with Debt", sourceUrl: "https://www.consumerfinance.gov/owning-a-home/prepare/" },
  { q: "What is mortgage points and should I buy them?", a: "Discount points are prepaid interest — you pay a percentage of the loan upfront to reduce your rate. One point = 1% of the loan amount and typically reduces the rate by 0.25%. Whether to buy points depends on how long you'll stay: calculate the break-even point (cost of points divided by monthly savings). If you'll own the home longer than the break-even period (usually 4-7 years), buying points saves money. If you'll move sooner, skip them.", cat: "mortgage", source: "CFPB: Decide on Loan Term", sourceUrl: "https://www.consumerfinance.gov/owning-a-home/explore/decide-on-loan-term/" },
  { q: "What happens if I miss a mortgage payment?", a: "Day 1-15: Most lenders have a 15-day grace period with no penalty. Day 16-30: Late fee charged (typically 3-6% of payment). Day 30+: Reported to credit bureaus, damaging your score significantly. Day 90+: Default notice sent. Day 120+: Foreclosure process may begin (timeline varies by state — judicial foreclosure takes longer). If you're struggling, contact your servicer immediately — options include forbearance, loan modification, and repayment plans. Don't ignore it.", cat: "mortgage", source: "CFPB: Having Trouble Making Mortgage Payments?", sourceUrl: "https://www.consumerfinance.gov/housing/housing-insecurity/help-for-homeowners/trouble-paying-mortgage/" },

  // === MORE CLOSING PROCESS ===
  { q: "What is a contingency?", a: "A contingency is a condition in your purchase agreement that must be met for the sale to proceed. If the contingency isn't satisfied, you can usually back out without losing your earnest money. Common contingencies: financing (loan approval), inspection (property condition), appraisal (value verification), title (clear title), and sale of current home. Each has a deadline. Missing a deadline may waive your right to exercise the contingency.", cat: "closing", source: "CFPB: Make an Offer", sourceUrl: "https://www.consumerfinance.gov/owning-a-home/close/make-offer/" },
  { q: "What is a title search and how long does it take?", a: "A title search examines public records to verify clear ownership and identify any liens, judgments, or encumbrances. It typically takes 1-2 weeks but can take longer for complex properties or if issues are discovered that need resolution. The title company traces every transfer of ownership, checks for outstanding debts, verifies legal descriptions, and identifies easements or restrictions. Issues are found in approximately 1 out of 3 searches. Source: ALTA", cat: "closing" },
  { q: "What is prorating and how does it work?", a: "Prorating divides costs between buyer and seller based on the closing date. Common prorated items: property taxes (seller pays through closing date, buyer pays the rest), HOA dues, utility bills, and prepaid insurance. For example, if property taxes are $6,000/year and you close on March 31, the seller pays for January-March ($1,500) and you're responsible for April-December. Your settlement agent handles these calculations on the Closing Disclosure.", cat: "closing", source: "CFPB: Understand Closing Costs", sourceUrl: "https://www.consumerfinance.gov/owning-a-home/close/understand-closing-costs/" },
  { q: "What is recording and why does it matter?", a: "Recording is the act of filing your deed (and deed of trust) with the county recorder's office, making your ownership a matter of public record. Until recording happens, your ownership isn't official. Recording typically occurs the same day as closing (in 'wet' closing states) or within 1-3 days. The settlement agent handles this. Recording fees (typically $50-250) are a closing cost. After recording, you receive a confirmation and eventually the original recorded deed.", cat: "closing", source: "CFPB: What Happens at Closing?", sourceUrl: "https://www.consumerfinance.gov/ask-cfpb/what-is-a-mortgage-closing-what-happens-at-the-closing-en-176/" },
  { q: "Can my closing be delayed?", a: "Yes — delays are common. Common causes: appraisal comes in low (requiring renegotiation), title search reveals issues needing resolution, lender underwriting requests additional documentation, inspection reveals major problems, buyer's financial situation changes (new debt, job change), document errors requiring corrections, and wire transfer issues. Build a 1-2 week buffer into your moving timeline. Rate lock extensions may cost extra if closing is delayed.", cat: "closing", source: "CFPB: Closing Process FAQ", sourceUrl: "https://www.consumerfinance.gov/owning-a-home/mortgage-closing/" },

  // === MORE COSTS ===
  { q: "What are transfer taxes?", a: "Transfer taxes (also called deed stamps, documentary stamps, or conveyance taxes) are state and/or local taxes imposed when property ownership transfers. They're calculated as a percentage of the sale price or a flat rate per dollar of value. Who pays varies by state and is often negotiable. Some states have no transfer tax (like Texas). Others are significant — New York City's combined rate can exceed 2%. These are zero-tolerance fees under TRID — they cannot increase from your Loan Estimate.", cat: "costs", source: "CFPB: Closing Costs", sourceUrl: "https://www.consumerfinance.gov/owning-a-home/close/understand-closing-costs/" },
  { q: "What is a home warranty and should I get one?", a: "A home warranty is a service contract covering repair or replacement of major home systems and appliances (HVAC, plumbing, electrical, kitchen appliances) for one year. Cost: $300-600. NOT the same as homeowner's insurance (which covers damage from disasters). Sellers sometimes provide a warranty as a selling incentive. Whether it's worth it depends on the home's age and condition. Read the contract carefully — exclusions, coverage limits, and service call fees vary.", cat: "costs", source: "FTC: Home Warranties", sourceUrl: "https://consumer.ftc.gov/articles/home-warranties" },
  { q: "How much should I budget for moving costs?", a: "For a local move (under 50 miles): $1,000-$3,000 for professional movers, or $200-$500 for a rental truck. Long-distance (over 100 miles): $3,000-$10,000+ depending on distance and volume. Additional costs: packing supplies ($100-300), storage if needed ($100-300/month), utility setup fees, address change costs, and cleaning. Budget 1-2% of your home price for immediate move-in expenses (cleaning, minor repairs, window coverings, locks).", cat: "costs" },

  // === MORE INSPECTIONS ===
  { q: "What is radon and should I test for it?", a: "Radon is a naturally occurring radioactive gas that seeps into homes from the ground. It's the #2 cause of lung cancer after smoking. The EPA recommends testing EVERY home — radon levels vary block by block, not just by region. Testing costs $100-200. If levels exceed 4 pCi/L, mitigation systems ($800-1,500) can reduce radon by up to 99%. Many buyers make testing part of their inspection contingency. Source: EPA", cat: "inspection", source: "EPA: Radon in Homes", sourceUrl: "https://www.epa.gov/radon" },
  { q: "Should I attend the home inspection?", a: "Absolutely — attending is one of the most valuable things you can do as a buyer. Walking through the home with the inspector gives you a hands-on education about the property's systems, maintenance needs, and any issues. You can ask questions in real-time, see problems firsthand, and understand the severity of findings. Most inspections take 2-4 hours. Bring a notebook and camera. Your inspector should encourage your presence.", cat: "inspection", source: "ASHI: What to Expect During an Inspection", sourceUrl: "https://www.homeinspector.org/" },
  { q: "What is a 4-point inspection?", a: "A 4-point inspection is a limited inspection that examines only four major systems: roof, electrical, plumbing, and HVAC. It's typically required by insurance companies (not lenders) for older homes — usually 20-30+ years old — before they'll issue a homeowner's insurance policy. It's NOT a substitute for a full home inspection. Cost: $100-200. The insurance company wants to assess the risk of these four systems failing.", cat: "inspection" },

  // === MORE RIGHTS ===
  { q: "What is the Fair Housing Act?", a: "Federal law prohibiting discrimination in housing based on race, color, national origin, religion, sex, familial status, and disability. It applies to selling, renting, financing, and advertising housing. If you believe you've experienced discrimination during the homebuying process — from a lender, real estate agent, seller, or anyone else — you can file a complaint with HUD (hud.gov) or call 1-800-669-9777. Many states add additional protected classes. Source: HUD", cat: "rights", source: "HUD: Fair Housing Act Overview", sourceUrl: "https://www.hud.gov/program_offices/fair_housing_equal_opp/fair_housing_act_overview" },
  { q: "What if the seller doesn't disclose a known defect?", a: "In most states, sellers are required to disclose known material defects. If a seller knowingly conceals a defect and you discover it after closing, you may have legal recourse — depending on your state's disclosure laws. Title insurance may cover certain undisclosed issues (like liens or encumbrances). For physical defects (foundation, mold, water damage), you may need to pursue the seller through the courts. This is why a thorough inspection before closing is critical.", cat: "rights" },
  { q: "Can I back out of a home purchase?", a: "It depends on your contingencies. With an inspection contingency, you can back out if the inspection reveals significant issues. With a financing contingency, you can exit if your loan falls through. With an appraisal contingency, you can walk if the home appraises below the purchase price. Without these contingencies, backing out typically means forfeiting your earnest money. After all contingencies expire, you're generally obligated to close or face potential legal action from the seller.", cat: "rights" },

  // === MORE AFTER CLOSING ===
  { q: "When is my first mortgage payment due?", a: "Your first payment is typically due on the first day of the second month after closing. For example, if you close on March 15, your first payment is usually due May 1. You pay prepaid interest at closing to cover March 15-31, then skip April entirely, and your regular payments begin May 1. This is normal — you're not 'skipping' a payment. Set up autopay immediately to avoid forgetting.", cat: "after", source: "CFPB: First Mortgage Payment", sourceUrl: "https://www.consumerfinance.gov/ask-cfpb/when-is-my-first-mortgage-payment-due-en-2011/" },
  { q: "Should I refinance?", a: "Consider refinancing when: rates drop 0.5-1% below your current rate, your credit score has significantly improved, you want to switch from adjustable to fixed rate, you want to remove PMI (if your home value increased enough), or you need to access equity through a cash-out refinance. Calculate the break-even point: total refinance costs divided by monthly savings. If you'll own the home longer than the break-even period, refinancing makes sense. New title insurance is typically needed.", cat: "after", source: "CFPB: When to Refinance", sourceUrl: "https://www.consumerfinance.gov/ask-cfpb/when-is-refinancing-your-mortgage-a-good-idea-en-158/" },
  { q: "What is a homestead exemption?", a: "A homestead exemption reduces the taxable value of your primary residence for property tax purposes. Rules vary by state — some offer a fixed dollar reduction (like $50,000 off assessed value), others a percentage reduction. You usually must apply within a specific timeframe after purchasing. In some states (like Florida and Texas), homestead exemptions also provide additional legal protections against creditors and forced sale. Check with your county tax assessor.", cat: "after", source: "Tax Foundation: Property Tax Exemptions", sourceUrl: "https://taxfoundation.org/data/all/state/property-taxes-by-state-county/" },
  { q: "How do I change the name on my deed?", a: "To add or remove someone from your deed (after marriage, divorce, inheritance, or estate planning), you'll need a new deed prepared and recorded with the county. This typically requires: a real estate attorney to prepare the deed, notarization of signatures, recording with the county recorder, and notification to your lender (important — some loans have a 'due on sale' clause). Title insurance for the new deed is recommended. Don't attempt this without legal guidance.", cat: "after", source: "CFPB: What Is a Deed?", sourceUrl: "https://www.consumerfinance.gov/ask-cfpb/what-is-a-mortgage-closing-what-happens-at-the-closing-en-176/" },
  { q: "What is a home equity line of credit (HELOC)?", a: "A HELOC is a revolving line of credit secured by your home equity. It works like a credit card — you can borrow up to your credit limit, repay, and borrow again during the 'draw period' (typically 10 years). After that, the 'repayment period' begins (typically 20 years). HELOCs usually have variable interest rates. Most lenders require at least 15-20% equity. A new title search is required to verify no additional liens exist. Use responsibly — your home is the collateral.", cat: "after", source: "CFPB: What Is a HELOC?", sourceUrl: "https://www.consumerfinance.gov/ask-cfpb/what-is-a-home-equity-line-of-credit-en-107/" },

  // === MORE FRAUD ===
  { q: "What is seller impersonation fraud?", a: "A growing scam where criminals impersonate property owners — often targeting vacant land, rental properties, or out-of-state owners. They create fake IDs, forge deeds, and attempt to sell property they don't own. Title searches and title insurance protect against this, but the scam can still cause delays and legal headaches. Red flags: seller unwilling to meet in person, wants to close unusually fast, provides wire instructions for funds to go overseas. Source: FBI", cat: "fraud", source: "FBI IC3: Real Estate Fraud Advisory", sourceUrl: "https://www.ic3.gov/" },
  { q: "What is a Business Email Compromise (BEC) attack?", a: "BEC is the primary vehicle for real estate wire fraud. Hackers gain access to a real email account (agent, lender, or title company) and monitor the conversation, waiting for closing to approach. They then send an email — from the real account or a convincing lookalike — with fraudulent wire instructions. BEC accounted for $2.77 billion in losses across all industries in 2024. In real estate, it's the most common attack vector. Multi-factor authentication is the #1 defense. Source: FBI IC3", cat: "fraud", source: "FBI IC3 2024 Internet Crime Report", sourceUrl: "https://www.ic3.gov/" },

  // === MORE TITLE INSURANCE ===
  { q: "Do I need title insurance if I'm paying cash?", a: "There's no lender requiring it, but owner's title insurance is even MORE important for cash buyers. Without a mortgage lender providing an extra layer of review, you're solely responsible for ensuring the title is clear. A title search and owner's policy protect your entire investment — which is 100% of the purchase price when paying cash. The one-time cost (0.5-1% of price) is negligible compared to the risk of an uninsured title claim.", cat: "insurance", source: "CFPB: Owner's Title Insurance", sourceUrl: "https://www.consumerfinance.gov/ask-cfpb/what-is-owners-title-insurance-en-164/" },
  { q: "Does title insurance cover boundary disputes?", a: "The standard ALTA Owner's Policy covers certain boundary issues — specifically, if someone else has an easement or right to use your land, or if you lack legal access. For more comprehensive boundary protection, ask about a survey endorsement, which extends coverage to matters a survey would reveal (encroachments, boundary line discrepancies). Getting a survey before closing is recommended, especially for rural properties or when fences/structures are near property lines.", cat: "insurance" },
  { q: "What is title insurance for a condo?", a: "Condos have unique title considerations. Your owner's policy covers your individual unit, but common areas are typically covered under the HOA's master policy. Key condo-specific title issues: HOA liens (for unpaid dues), special assessments, right of first refusal provisions, and restrictions on use or rental. Ask about ALTA's condominium endorsement, which provides additional coverage specific to condo ownership. Review the HOA's financial health and reserve fund before purchasing.", cat: "insurance" },
  { q: "Is title insurance required by law?", a: "No state requires owner's title insurance by law — it's optional but strongly recommended. However, almost all mortgage lenders require a lender's title insurance policy as a condition of the loan. The lender's policy only protects the bank — not you. That's why purchasing a separate owner's policy is so important. It's the only protection you have if someone challenges your ownership or a hidden lien surfaces after closing.", cat: "insurance", source: "CFPB: Lender's Title Insurance", sourceUrl: "https://www.consumerfinance.gov/ask-cfpb/what-is-lenders-title-insurance-en-163/" },

  // === MORE BASICS ===
  { q: "What is a survey and do I need one?", a: "A property survey determines the exact boundaries, dimensions, and location of structures on your land. It shows: property lines, easements, encroachments (structures crossing boundaries), setback violations, and flood zone status. Some lenders and title companies require a survey; others accept an existing one. A new survey costs $300-700. It's especially important for: rural properties, properties with fences or outbuildings near boundaries, waterfront properties, and any property where boundaries are unclear.", cat: "basics" },
  { q: "What is a quitclaim deed?", a: "A quitclaim deed transfers whatever ownership interest the grantor may have — without making any guarantees about the quality of that title. It provides NO warranty that the grantor actually owns the property or that the title is clear. Quitclaim deeds are commonly used between family members, to add/remove a spouse after marriage/divorce, or to correct a name on a deed. They should NEVER be used for a standard purchase — always insist on a warranty deed for purchases.", cat: "basics" },
  { q: "What is a short sale?", a: "A short sale occurs when a homeowner sells their property for less than the outstanding mortgage balance, with the lender's approval. The lender agrees to accept less than what's owed to avoid the cost and time of foreclosure. Short sales take longer to close (3-6 months or more) because the lender must approve the sale price. Title insurance is especially important in short sales — there may be additional liens, judgments, or complications. Source: NAR", cat: "basics", source: "NAR: Short Sales Guide", sourceUrl: "https://www.nar.realtor/" },
  { q: "What is foreclosure and how does it affect title?", a: "Foreclosure is the legal process by which a lender takes possession of a property when the borrower defaults on the mortgage. Foreclosure can create title complications: junior liens may or may not be extinguished, there may be redemption periods allowing the former owner to reclaim the property, and IRS tax liens have special rules. Title insurance is critical when buying a foreclosure — it protects against these complex title issues that are common in distressed properties.", cat: "basics", source: "CFPB: Foreclosure", sourceUrl: "https://www.consumerfinance.gov/housing/housing-insecurity/help-for-homeowners/" },

  // === PROPERTY TAXES ===
  { q: "How are property taxes calculated?", a: "Property taxes are calculated by multiplying your property's assessed value by the local tax rate (mill rate). The assessed value is determined by your county assessor and may differ from market value. Tax rates are set by multiple jurisdictions: county, city, school district, and special districts. Your total rate is the sum of all applicable rates. Rates vary dramatically — from 0.27% in Hawaii to over 2.3% in New Jersey. Contact your county assessor's office for your exact rate.", cat: "costs", source: "Tax Foundation: Property Taxes by State", sourceUrl: "https://taxfoundation.org/data/all/state/property-taxes-by-state-county/" },
  { q: "Can I appeal my property tax assessment?", a: "Yes. If you believe your property's assessed value is too high, you can file an appeal with your county assessor's office. Deadlines are strict — typically 30-90 days after receiving your assessment notice. To build your case: gather comparable sales data for similar homes that sold for less, document any condition issues that reduce value, and note any errors in the property description (wrong square footage, bedroom count, etc.). Many homeowners successfully reduce their assessed value through appeals.", cat: "costs", source: "Tax Foundation: Property Tax Data", sourceUrl: "https://taxfoundation.org/data/all/state/property-taxes-by-state-county/" },
  { q: "What is a property tax escrow?", a: "Most lenders collect property taxes monthly through your escrow account rather than having you pay the lump sum directly. Your monthly mortgage payment includes principal, interest, taxes, and insurance (PITI). The lender holds the tax portion in escrow and pays your property tax bill when it's due. Your lender must provide an annual escrow analysis showing deposits, payments, and any surplus or shortage. If there's a shortage, your monthly payment may increase.", cat: "costs", source: "CFPB: What Is an Escrow Account?", sourceUrl: "https://www.consumerfinance.gov/ask-cfpb/what-is-an-escrow-or-impound-account-en-140/" },

  // === HOA & CONDOS ===
  { q: "What should I know about HOA fees before buying?", a: "Before buying in an HOA community, review: monthly dues and what they cover (landscaping, pool, insurance, reserves), the HOA's financial statements and reserve fund health, any pending or planned special assessments, CC&Rs (covenants, conditions, and restrictions) that limit what you can do with your property, meeting minutes for the past year, and any pending litigation. A financially unhealthy HOA can result in special assessments of thousands of dollars. Your title search will reveal any HOA liens.", cat: "costs", source: "CFPB: Understand Closing Costs", sourceUrl: "https://www.consumerfinance.gov/owning-a-home/close/understand-closing-costs/" },
  { q: "What is a special assessment?", a: "A special assessment is a one-time charge levied by your HOA or local government for a specific purpose — like a new roof on a condo building, road repaving, or sewer system upgrade. HOA special assessments can range from a few hundred to tens of thousands of dollars and may be payable as a lump sum or spread over months. Before buying, ask the HOA if any special assessments are planned or pending. Title searches may reveal existing special assessment liens.", cat: "costs", source: "CFPB: What Is an HOA?", sourceUrl: "https://www.consumerfinance.gov/owning-a-home/" },
  { q: "How is buying a condo different from a house?", a: "Key differences: you own the unit interior but the building structure, common areas, and land are owned collectively through the HOA. You'll pay monthly HOA dues on top of your mortgage. The HOA's master insurance policy covers the building, but you need an HO-6 policy for your unit's interior. Condo financing may require FHA condo approval or Fannie Mae eligibility. Title insurance covers your unit ownership plus any issues with the HOA's ownership of common areas.", cat: "closing", source: "CFPB: Owning a Home", sourceUrl: "https://www.consumerfinance.gov/owning-a-home/" },

  // === FIRST-TIME BUYER SPECIFIC ===
  { q: "What is a first-time homebuyer program?", a: "State and local programs offering assistance to first-time buyers (and sometimes repeat buyers who haven't owned in 3+ years). Common benefits: down payment grants, forgivable loans, below-market interest rates, reduced mortgage insurance, and closing cost assistance. Every state has a Housing Finance Agency (HFA) with programs. Income limits and purchase price caps typically apply. HUD-approved housing counselors can help you find programs in your area. Source: NCSHA", cat: "mortgage", source: "National Council of State Housing Agencies (NCSHA)", sourceUrl: "https://www.ncsha.org/homebuyer-programs/" },
  { q: "How much do I need for a down payment?", a: "It depends on the loan type: Conventional (3-20%), FHA (3.5% with 580+ credit), VA (0% for eligible veterans), USDA (0% for eligible rural areas). While 20% avoids PMI on conventional loans, most first-time buyers put down significantly less — the national median is about 8%. Down payment assistance programs can cover some or all of the down payment. Remember: you also need cash for closing costs (2-5%), moving expenses, and reserves.", cat: "mortgage", source: "CFPB: Explore Loan Options", sourceUrl: "https://www.consumerfinance.gov/owning-a-home/explore/decide-on-loan-term/" },
  { q: "What credit score do I need to buy a home?", a: "Minimum scores by loan type: FHA (580 for 3.5% down, 500 for 10% down), Conventional (620), VA (no official minimum, but lenders typically want 620+), USDA (640). However, minimum scores get you approved — they don't get you the best rates. Aim for 740+ for the best conventional rates and lowest PMI. Each 20-point improvement can save 0.125-0.25% on your rate, which translates to thousands over 30 years. Check your score free at annualcreditreport.com.", cat: "mortgage", source: "CFPB: Explore Loan Choices", sourceUrl: "https://www.consumerfinance.gov/owning-a-home/explore/decide-on-loan-term/" },
  { q: "Should I pay off all my debt before buying?", a: "Not necessarily. What matters most is your debt-to-income ratio (DTI). Pay off high-interest debts that significantly impact your monthly payments, but don't drain your savings — you'll need cash for down payment, closing costs, and reserves. Strategic debt payoff: eliminate credit card balances first (highest impact on both DTI and credit score), then consider paying down car loans if they push your DTI over limits. Keep credit cards open after paying them off.", cat: "mortgage", source: "CFPB: Determine How Much You Can Afford", sourceUrl: "https://www.consumerfinance.gov/owning-a-home/explore/decide-how-much/" },

  // === INSURANCE ===
  { q: "What's the difference between homeowner's insurance and title insurance?", a: "Homeowner's insurance protects against FUTURE events — fire, storms, theft, liability. You pay annual premiums and file claims when damage occurs. Title insurance protects against PAST events — hidden liens, ownership disputes, forged documents, errors in records. You pay a ONE-TIME premium at closing for lifetime coverage. Both are essential but protect against completely different risks. Your lender requires both, but only the owner's title policy protects YOU.", cat: "insurance" },
  { q: "What is an owner's title insurance endorsement?", a: "An endorsement adds or modifies coverage on your standard title policy. Common endorsements include: survey coverage (boundary disputes), zoning compliance, environmental protection lien, condominium coverage, adjustable rate mortgage protection, and inflation/market value adjustments. Endorsements cost extra ($25-200 each) but can significantly expand your protection. Ask your title company which endorsements are available and recommended for your property type.", cat: "insurance" },
  { q: "Does title insurance cover me if the property is in a flood zone?", a: "Title insurance does not cover flood damage — that's what flood insurance is for. However, title insurance DOES cover issues related to flood zone designations: if a previous owner had restrictions or obligations related to flood zones that weren't disclosed, or if there are outstanding FEMA liens. Separately, if your property is in a FEMA-designated flood zone, your lender will require flood insurance. Check FEMA's flood map at msc.fema.gov.", cat: "insurance" },

  // === INSPECTION DEEP DIVES ===
  { q: "What is a pre-drywall inspection for new construction?", a: "The most valuable inspection for new construction — done before drywall is installed so you can see framing, plumbing, electrical, HVAC, and insulation. Once walls are closed, these systems are hidden for the life of the home. A pre-drywall inspection catches: improperly framed walls, missing fire blocking, incorrectly run plumbing, reversed hot/cold lines, electrical code violations, and insufficient insulation. Cost: $300-400. Schedule it as soon as rough-in work is complete.", cat: "inspection", source: "InterNACHI: New Construction Inspections", sourceUrl: "https://www.nachi.org/" },
  { q: "What is an 11-month warranty inspection?", a: "For new construction homes with a builder's 1-year warranty, schedule an inspection at the 11-month mark — before the warranty expires. This catches issues that develop during the first year: settling cracks, HVAC performance problems, drainage issues, window seal failures, and minor defects the builder is obligated to fix under warranty. Present the inspector's report to your builder and request repairs before the warranty period ends. Cost: $300-400.", cat: "inspection" },
  { q: "What does a home inspection NOT cover?", a: "Standard inspections are visual — inspectors can only evaluate what's visible and accessible. NOT covered: inside walls, under foundations, behind finished surfaces, swimming pools (separate pool inspection needed), wells and septic (separate inspections), environmental hazards like asbestos/lead unless visually obvious, pest/termite damage (separate WDI inspection), and code compliance (inspectors note concerns but aren't code officials). Ask about add-on services for areas of concern.", cat: "inspection", source: "ASHI: Standards of Practice", sourceUrl: "https://www.homeinspector.org/" },

  // === DOCUMENTS DEEP DIVES ===
  { q: "What is the difference between the Loan Estimate and Closing Disclosure?", a: "The Loan Estimate is your INITIAL look at costs (received within 3 days of application). The Closing Disclosure is the FINAL version (received 3 days before closing). Compare them line by line. Key tolerance rules: zero-tolerance fees (origination, transfer taxes) CANNOT increase. 10%-tolerance fees (title services, recording) can increase up to 10% in aggregate. No-limit fees (services you chose, prepaids) can change freely. If zero-tolerance fees increased, your lender must refund the difference. Source: CFPB", cat: "documents", source: "CFPB: Compare Loan Estimate to Closing Disclosure", sourceUrl: "https://www.consumerfinance.gov/owning-a-home/closing-disclosure/" },
  { q: "What is a title insurance binder?", a: "A title insurance binder is a temporary contract obligating the title company to issue a policy upon meeting specified conditions. It's essentially a promise to insure — similar to how a homeowner's insurance binder works. The binder lists the proposed insured, the property, the coverage amount, and any conditions or exceptions. The final policy replaces the binder after closing and recording. Keep both documents.", cat: "documents" },
  { q: "What is a settlement statement?", a: "The settlement statement (now replaced by the Closing Disclosure for most transactions) is the complete accounting of all funds in the transaction. It shows every fee, credit, proration, and disbursement for both buyer and seller. For transactions not covered by TRID (cash sales, commercial transactions), the HUD-1 settlement statement may still be used. Review every line item and ask about anything you don't understand before signing.", cat: "documents", source: "CFPB: Settlement Statement vs Closing Disclosure", sourceUrl: "https://www.consumerfinance.gov/owning-a-home/closing-disclosure/" },

  // === RIGHTS DEEP DIVES ===
  { q: "What is the TRID rule?", a: "TILA-RESPA Integrated Disclosure (TRID) is the CFPB rule that combined four old disclosure forms into two new standardized ones: the Loan Estimate and Closing Disclosure. Key provisions: Loan Estimate within 3 business days of application, Closing Disclosure 3 days before closing, fee tolerance limits, and specific triggers for revised disclosures. TRID applies to most residential mortgages (not commercial, reverse mortgages, or HELOCs). It gives consumers the time and information needed to make informed decisions. Source: CFPB", cat: "rights", source: "CFPB: TILA-RESPA Integrated Disclosure Rule", sourceUrl: "https://www.consumerfinance.gov/compliance/compliance-resources/mortgage-resources/tila-respa-integrated-disclosures/" },
  { q: "Can I sue my title company?", a: "Title insurance is a contract — if your title company fails to honor a covered claim, you may have legal recourse. Common issues: denial of a legitimate claim, failure to defend your title, or negligence in the title search that caused you loss. First, file a complaint with your state's department of insurance. If unresolved, consult a real estate attorney. Most title insurance disputes are resolved through the claims process, arbitration, or mediation rather than litigation.", cat: "rights", source: "NAIC: State Insurance Departments", sourceUrl: "https://content.naic.org/state-insurance-departments" },
  { q: "What protections do I have if my lender fails?", a: "If your lender goes bankrupt or is taken over, your loan terms (rate, balance, payment) cannot change. Your loan will be transferred to a new servicer who must honor the original terms. The FDIC insures deposits up to $250,000, but your mortgage is a debt you owe — not a deposit. Your title insurance remains valid regardless of what happens to your lender. The biggest risk is confusion during the transition — keep records of all payments.", cat: "rights", source: "CFPB: When Your Loan Servicer Changes", sourceUrl: "https://www.consumerfinance.gov/ask-cfpb/what-happens-when-my-mortgage-is-sold-en-175/" },

  // === AFTER CLOSING DEEP DIVES ===
  { q: "What maintenance should I do immediately after moving in?", a: "First 30 days: change all locks and garage codes, test smoke/CO detectors and replace batteries, locate the main water shutoff, gas shutoff, and electrical panel, change HVAC filters, check water heater temperature (120°F recommended), inspect attic and crawlspace, test all GFCI outlets, and document the condition of everything with photos. First 90 days: have the chimney cleaned if you have a fireplace, service the HVAC system, and address any issues noted in your home inspection.", cat: "after", source: "CFPB: After You Close", sourceUrl: "https://www.consumerfinance.gov/ask-cfpb/what-should-i-do-before-during-and-after-the-mortgage-closing-process-en-1907/" },
  { q: "What is a home warranty and is it worth it?", a: "A home warranty is a service contract (not insurance) covering repair/replacement of major systems and appliances for one year. Cost: $300-600 annually plus service call fees ($75-125 per visit). Worth it if: your home is older with aging systems, you don't have emergency savings for repairs, or the seller provides one as a closing incentive. NOT worth it if: your home is new (builder warranty covers it), you have strong emergency savings, or the contract has excessive exclusions. Always read the fine print.", cat: "after", source: "FTC: Home Warranties", sourceUrl: "https://consumer.ftc.gov/articles/home-warranties" },
  { q: "How do I file for a homestead exemption?", a: "A homestead exemption reduces your property taxes on your primary residence. To file: contact your county tax assessor's office (or check their website) within the filing deadline (varies by state — often within 1 year of purchase). You'll need: proof of ownership (deed), proof of residency (driver's license with property address), and Social Security number. In some states, homestead exemptions save thousands per year and provide additional legal protections against creditors. Don't miss the deadline.", cat: "after" },
  { q: "When should I consider refinancing my mortgage?", a: "Consider refinancing when: (1) rates drop 0.5-1%+ below your current rate, (2) your credit score improved significantly since purchase, (3) you want to switch from adjustable to fixed, (4) you need to remove PMI and have 20%+ equity, (5) you want to tap equity (cash-out refi), or (6) you want to shorten your term (30-year to 15-year). Calculate the break-even: total refi costs / monthly savings = months to recoup. Only refinance if you'll own the home longer than the break-even. New title insurance is typically required.", cat: "after", source: "CFPB: When to Refinance", sourceUrl: "https://www.consumerfinance.gov/ask-cfpb/when-is-refinancing-your-mortgage-a-good-idea-en-158/" },

  // === CLOSING PROCESS ADDITIONS ===
  { q: "What is power of attorney at closing?", a: "If you can't attend your closing in person, you can authorize someone to sign on your behalf through a power of attorney (POA). The POA must: be specific to the real estate transaction (not a general POA), name the exact property address, be notarized, be approved by your lender in advance, and comply with your state's requirements. Not all lenders accept POA closings, and some title companies have additional requirements. Arrange this well before your closing date — last-minute POA requests are often denied.", cat: "closing" },
  { q: "What happens if the seller can't deliver clear title?", a: "If the title search reveals issues the seller can't resolve before closing (outstanding liens, ownership disputes, unreleased mortgages), you have options: (1) extend the closing date to give more time for resolution, (2) negotiate a price reduction or escrow holdback for the cost of resolving the issue, (3) accept the title with the known defect (not recommended), or (4) exercise your title contingency and cancel the transaction. Title insurance won't cover defects you knowingly accepted.", cat: "closing" },
  { q: "What is a closing escrow holdback?", a: "An escrow holdback is when a portion of the seller's proceeds are held in escrow after closing to cover a specific obligation — like completing a repair, resolving a title issue, or finishing work agreed upon in negotiations. The funds are released when the condition is met (verified by the buyer or their agent). The holdback amount, conditions for release, and timeline are documented in the purchase agreement. This protects the buyer when an issue can't be resolved before closing.", cat: "closing" },

  // === MORTGAGE ADDITIONS ===
  { q: "What is a VA funding fee?", a: "The VA funding fee is a one-time charge on VA loans that helps offset the cost of the program to taxpayers. For first-time use with zero down, the fee is 2.15% of the loan amount (3.3% for subsequent use). The fee decreases with larger down payments: 1.5% with 5%+ down, 1.25% with 10%+ down. The fee can be financed into the loan (adding it to your loan balance) or paid at closing. Veterans with service-connected disabilities are EXEMPT from the funding fee entirely. Source: VA.gov", cat: "mortgage", source: "VA.gov: VA Home Loan Funding Fee", sourceUrl: "https://www.va.gov/housing-assistance/home-loans/funding-fee/" },
  { q: "What is FHA mortgage insurance and how long does it last?", a: "FHA loans require two types of mortgage insurance: Upfront MIP (UFMIP) of 1.75% of the loan (added to your loan balance), and Annual MIP of 0.55% for most borrowers (paid monthly). For loans with LTV > 90% at origination (less than 10% down), annual MIP is required for the LIFE of the loan. For LTV ≤ 90%, MIP drops off after 11 years. The only way to remove FHA MIP early on a high-LTV loan is to refinance into a conventional loan when you have 20%+ equity. Source: FHA.com", cat: "mortgage", source: "FHA.com: FHA Mortgage Insurance Requirements", sourceUrl: "https://www.fha.com/fha_requirements_mortgage_insurance" },
  { q: "What is a USDA loan and who qualifies?", a: "USDA Rural Development loans offer zero down payment for eligible properties in rural and suburban areas (covering more areas than most people expect — check the USDA eligibility map). Income limits apply: typically 115% of area median income. The upfront guarantee fee is 1% (added to loan) and annual fee is 0.35% (lowest MI of any loan type). Credit score minimum is typically 640. USDA loans require title insurance and the property must be your primary residence. Source: USDA.gov", cat: "mortgage", source: "USDA Rural Development: Single Family Housing", sourceUrl: "https://www.rd.usda.gov/programs-services/single-family-housing-programs" },

  // === ESSENTIAL QUESTIONS EVERY BUYER SHOULD ASK AT CLOSING ===
  { q: "What questions should I ask at the closing table?", a: "Before signing anything: (1) Is this the same interest rate I was quoted? (2) Do the closing costs match my Closing Disclosure? (3) Are there any fees that weren't on my Loan Estimate? (4) When will my deed be recorded? (5) When is my first mortgage payment due? (6) Who do I contact if I have questions after closing? (7) When will I receive my final title insurance policy? (8) Are there any documents I should review with my attorney first? (9) Has everything from the final walk-through been addressed? Don't rush — this is the biggest financial transaction of your life.", cat: "closing", source: "CFPB: Close the Deal Guide", sourceUrl: "https://www.consumerfinance.gov/owning-a-home/close/close-the-deal/" },
  { q: "What should I verify before signing the Closing Disclosure?", a: "Before your closing appointment, verify: (1) Your name is spelled correctly, (2) The property address matches, (3) The loan amount, interest rate, and monthly payment match your Loan Estimate, (4) No new fees appeared, (5) Your earnest money deposit is credited, (6) Seller concessions are reflected, (7) Prepaid items are calculated correctly, (8) Owner's title insurance is included, (9) The closing date is correct, (10) Contact information for all parties is accurate. If ANYTHING looks wrong, contact your lender and settlement agent BEFORE the closing appointment.", cat: "documents", source: "CFPB: Closing Disclosure Explainer", sourceUrl: "https://www.consumerfinance.gov/owning-a-home/closing-disclosure/" },
  { q: "What are the biggest mistakes buyers make at closing?", a: "Common closing mistakes: (1) Not reading the Closing Disclosure carefully, (2) Wiring money without phone verification, (3) Making large purchases or credit changes before closing, (4) Waiving the inspection contingency, (5) Skipping owner's title insurance, (6) Not shopping for title and settlement services, (7) Ignoring Schedule B exceptions on the title commitment, (8) Not attending the home inspection, (9) Missing contingency deadlines, (10) Not budgeting for closing costs beyond the down payment. Each of these can cost thousands — or your entire investment.", cat: "closing" },
  { q: "What is the most important thing to know about closing?", a: "The single most important thing: NEVER wire money based solely on email instructions. Wire fraud is the #1 financial threat to homebuyers, with losses of $275.1 million in 2025. Always verify wiring instructions by calling your title company using a phone number you already have — not one from an email. Beyond that: read every document before signing, compare your Closing Disclosure to your Loan Estimate, get owner's title insurance, and don't be afraid to ask questions. Your settlement agent is there to help you understand what you're signing.", cat: "closing" },

  // === TAX DEDUCTIONS & FINANCIAL ===
  { q: "What home expenses are tax deductible?", a: "Common deductions for homeowners: mortgage interest (on loans up to $750,000 for homes purchased after Dec 2017), property taxes (up to $10,000 combined state and local taxes under SALT cap), mortgage insurance premiums (if your AGI is under limits), points paid at closing (either immediately or amortized), and home office expenses (if self-employed). Capital improvements aren't deductible annually but add to your cost basis, reducing capital gains when you sell. Consult a tax professional for your specific situation.", cat: "costs", source: "IRS: Deducting Mortgage Interest", sourceUrl: "https://www.irs.gov/publications/p936" },
  { q: "What is the mortgage interest deduction?", a: "You can deduct interest paid on mortgage debt up to $750,000 (for homes purchased after December 15, 2017) or $1,000,000 (for homes purchased before). This applies to your primary residence and one additional home. The deduction is only available if you itemize deductions rather than taking the standard deduction ($15,000 single / $30,000 married filing jointly for 2025). For many homeowners with smaller mortgages, the standard deduction may be more beneficial. Your lender sends Form 1098 annually showing interest paid.", cat: "costs", source: "IRS Publication 936: Home Mortgage Interest Deduction", sourceUrl: "https://www.irs.gov/publications/p936" },
  { q: "What is the capital gains exclusion when I sell?", a: "When you sell your primary residence, you can exclude up to $250,000 in capital gains from taxes ($500,000 for married couples filing jointly) if you've owned and lived in the home for at least 2 of the last 5 years. Capital gain = sale price minus cost basis (purchase price + capital improvements + selling costs). If your gain exceeds the exclusion, the excess is taxed at capital gains rates (0%, 15%, or 20% depending on income). Keep records of all improvements to maximize your cost basis.", cat: "after", source: "IRS: Sale of Your Home", sourceUrl: "https://www.irs.gov/taxtopics/tc701" },
  { q: "Should I set up an emergency fund before buying?", a: "Absolutely. Financial experts recommend having 3-6 months of expenses saved in addition to your down payment and closing costs. Homeownership comes with unexpected costs: HVAC failures ($3,000-8,000), roof repairs ($5,000-15,000), plumbing emergencies ($1,000-5,000), and appliance replacements ($500-3,000). Without reserves, a single major repair could put you in financial distress. Build this fund before you buy, not after.", cat: "mortgage", source: "CFPB: Prepare for Homeownership", sourceUrl: "https://www.consumerfinance.gov/owning-a-home/prepare/" },

  // === PROPERTY TYPES ===
  { q: "What should I know about buying a townhouse?", a: "Townhouses share walls with neighbors but you typically own the land beneath your unit. Key considerations: HOA fees (usually lower than condos since you maintain your own exterior in some communities), shared wall construction quality (fire rating, sound insulation), parking (assigned vs shared), and whether the HOA covers the roof and exterior. Title insurance covers your individual lot. Check the CC&Rs for restrictions on modifications, rentals, and pets.", cat: "closing" },
  { q: "What is a co-op and how is it different from a condo?", a: "In a co-op, you don't own real property — you own shares in a corporation that owns the building, plus a proprietary lease giving you the right to occupy a specific unit. Co-ops are common in New York City. Key differences from condos: the co-op board must approve all buyers (can reject without reason), financing is harder (fewer lenders, larger down payments), you can't freely rent your unit, and monthly fees are typically higher (include building mortgage, taxes, and maintenance). Title insurance works differently for co-ops.", cat: "basics", source: "NAR: Types of Housing", sourceUrl: "https://www.nar.realtor/" },
  { q: "What should I know about buying a manufactured or mobile home?", a: "Manufactured homes built after June 1976 are constructed to HUD federal standards (not local building codes). Key considerations: the home may be titled as personal property (like a vehicle) rather than real property — converting to real property is important for financing and title insurance. FHA, VA, and conventional loans are available but with additional requirements. Land ownership vs lot rental significantly affects value and financing. Title searches must cover both the home and the land.", cat: "basics" },
  { q: "How is buying land different from buying a home?", a: "Buying vacant land involves unique considerations: zoning restrictions (residential, commercial, agricultural), utility access (water, sewer, electric, gas — extending utilities can cost tens of thousands), soil testing and percolation tests (for septic systems), environmental assessments, flood zone status, access rights (legal road access), and survey requirements. Financing is harder — land loans typically require 20-50% down with higher interest rates. Title insurance is essential — land frequently has boundary, easement, and access issues.", cat: "basics" },

  // === NEGOTIATION & STRATEGY ===
  { q: "How do I make a competitive offer without overpaying?", a: "Research comparable sales (your agent can pull these), understand the local market conditions (buyer's vs seller's market), consider the seller's motivations (timeline, contingencies they'd prefer), and structure your offer strategically. Competitive moves beyond price: larger earnest money deposit, flexible closing date, pre-approval letter from a strong lender, waiving or shortening non-essential contingencies (never waive inspection), and clean offers with fewer conditions. Your agent's guidance is invaluable here.", cat: "closing" },
  { q: "How do I negotiate after a bad home inspection?", a: "After receiving the inspection report, categorize issues by severity: safety hazards (must be addressed), structural/mechanical issues (expensive to fix), maintenance items (normal wear), and cosmetic issues (not worth negotiating). Focus negotiations on the first two categories. Options: ask the seller to make repairs before closing, request a price reduction, ask for a closing cost credit, or negotiate an escrow holdback. Your agent will help you determine what's reasonable based on local norms. Don't nitpick minor items — it can kill the deal.", cat: "inspection" },
  { q: "What is an escalation clause?", a: "An escalation clause automatically increases your offer price up to a maximum amount if competing offers come in. For example: 'I offer $350,000 but will beat any competing offer by $2,000 up to a maximum of $380,000.' The clause triggers only if the seller has a bona fide competing offer. Pros: competitive without overpaying. Cons: reveals your maximum budget, may not be accepted by all sellers, and requires verification of competing offers. Common in hot markets.", cat: "closing" },
  { q: "Should I waive contingencies to win a bidding war?", a: "This is risky and should be done cautiously. Financing contingency: only waive if you have guaranteed funding or cash reserves to cover the gap. Appraisal contingency: only waive if you can cover the difference between the appraised value and purchase price in cash. Inspection contingency: NEVER waive entirely — instead, offer a 'pass/fail' inspection where you can only cancel for major structural or safety issues, not cosmetic concerns. Discuss risks with your agent before waiving any contingency.", cat: "closing" },

  // === SPECIFIC SCENARIOS ===
  { q: "What if the appraisal comes in lower than my offer?", a: "Four options: (1) Negotiate with the seller to lower the price to the appraised value, (2) Pay the difference between the appraised value and the purchase price out of pocket (increasing your down payment), (3) Challenge the appraisal by providing additional comparable sales to the lender — they may order a review or second appraisal, (4) Walk away using your appraisal contingency and get your earnest money back. Option 1 is most common. Your lender will only lend based on the appraised value, not the purchase price.", cat: "closing", source: "CFPB: Understanding Your Appraisal", sourceUrl: "https://www.consumerfinance.gov/ask-cfpb/what-is-a-home-appraisal-en-2086/" },
  { q: "What if I find problems during the final walk-through?", a: "The final walk-through is your last chance to verify the property's condition. If you find issues: minor items (damaged wall, missing fixture) — note them and ask the seller to fix or credit you at closing. Major items (water damage, removed fixtures that should stay, seller hasn't vacated) — do NOT proceed to closing until resolved. Contact your agent and settlement agent immediately. You can delay closing to address problems. Signing first and addressing later puts you at a severe disadvantage.", cat: "closing" },
  { q: "What happens if my loan falls through before closing?", a: "If your financing contingency is still active, you can cancel the purchase and get your earnest money back. If the contingency has expired, you may forfeit your earnest money. Common reasons loans fall through: job change, new debt, bank account changes, credit score drop, property doesn't meet lender requirements, or appraisal issues. To protect yourself: don't change anything financial after pre-approval, respond to lender document requests immediately, and keep your financing contingency active as long as possible.", cat: "mortgage", source: "CFPB: Closing Process Guide", sourceUrl: "https://www.consumerfinance.gov/owning-a-home/mortgage-closing/" },
  { q: "What is a 'subject to' transaction?", a: "In a 'subject to' transaction, the buyer takes ownership of the property while the existing mortgage remains in the seller's name. The buyer makes the mortgage payments but doesn't formally assume the loan. This is an advanced strategy with significant risks for both parties: the lender can call the loan due (due-on-sale clause), the buyer has no formal loan relationship, and the seller remains liable if the buyer stops paying. Title insurance and legal counsel are essential. This is NOT recommended for typical residential purchases.", cat: "mortgage" },

  // === CLOSING COSTS SPECIFICS ===
  { q: "What is origination and should I pay it?", a: "Origination fees are what the lender charges for processing, underwriting, and funding your loan — typically 0.5-1% of the loan amount. Some lenders charge a flat origination fee, others charge a percentage. This fee is negotiable and is one of the main items to compare across Loan Estimates. Some lenders offer 'no origination fee' loans but compensate with a slightly higher interest rate. Do the math: a lower fee with a higher rate may cost more over time.", cat: "costs", source: "CFPB: Understand Loan Options", sourceUrl: "https://www.consumerfinance.gov/owning-a-home/explore/decide-on-loan-term/" },
  { q: "What is the difference between prepaids and closing costs?", a: "Closing costs are fees for services rendered to complete the transaction: origination, appraisal, title search, settlement fee, recording fees, etc. Prepaids are advance payments for future recurring expenses: prepaid interest (from closing to month-end), first year's homeowner's insurance, initial property tax escrow deposit, and initial insurance escrow deposit. Both appear on your Closing Disclosure but serve different purposes. Prepaids can add $3,000-8,000+ depending on timing and location.", cat: "costs", source: "CFPB: Closing Costs Explained", sourceUrl: "https://www.consumerfinance.gov/owning-a-home/close/understand-closing-costs/" },
  { q: "What is the recording fee?", a: "Recording fees are charged by your county recorder's office to officially file your deed, deed of trust, and other documents in the public record. This makes your ownership official and gives public notice of the transaction. Fees vary by county — typically $50-250 total. Recording is a 10%-tolerance fee under TRID, meaning it can increase up to 10% from your Loan Estimate but not more. Your settlement agent handles the recording process.", cat: "costs", source: "CFPB: Closing Costs", sourceUrl: "https://www.consumerfinance.gov/owning-a-home/close/understand-closing-costs/" },

  // === TITLE & CLOSING INDUSTRY ===
  { q: "What is a settlement agent?", a: "The settlement agent (also called a closing agent, escrow officer, or closing attorney depending on your state) is the neutral third party who coordinates the closing. They: order and review the title search, prepare closing documents, calculate all fees and prorations, collect and disburse funds, ensure all conditions are met, explain documents to the buyer, record the deed and deed of trust, and issue the title insurance policies. In some states, an attorney is required; in others, a title company agent handles the closing.", cat: "closing", source: "CFPB: Who Should I Expect to See at Closing?", sourceUrl: "https://www.consumerfinance.gov/ask-cfpb/who-should-i-expect-to-see-at-my-mortgage-closing-en-1903/" },
  { q: "What are ALTA Best Practices?", a: "ALTA Best Practices is a comprehensive framework of 7 pillars that title and settlement companies adopt to protect consumers. The pillars cover: (1) licensing and education, (2) escrow account controls, (3) privacy and data security, (4) settlement procedures, (5) title policy production, (6) professional liability insurance, and (7) consumer complaint resolution. Companies that adopt Best Practices undergo regular assessments. When choosing a title company, ask if they follow ALTA Best Practices. Source: ALTA", cat: "basics" },
  { q: "What is an abstract of title?", a: "An abstract of title is a condensed history of all recorded documents affecting a property — deeds, mortgages, liens, judgments, wills, tax sales, easements, and other instruments. It's the foundation of the title search. In some regions (particularly the Midwest and parts of the South), abstracts are maintained as physical books that are updated with each transaction. In others, title plants (computerized databases) have replaced traditional abstracts. Either way, the abstract enables the title examiner to determine the current state of ownership.", cat: "basics" },
  { q: "What is a title plant?", a: "A title plant is a comprehensive, organized database of title information maintained by a title company — containing copies of recorded documents, maps, indexes, and other records needed to perform title searches. Title plants allow efficient, accurate searches without relying solely on county records (which may be incomplete or difficult to search). Building and maintaining a title plant is a significant investment — it's one of the reasons title companies are valuable and why their services cost what they do.", cat: "basics" },
  { q: "Who regulates title insurance?", a: "Title insurance is regulated at the state level by each state's department of insurance (or equivalent agency). Regulations cover: premium rates (which may be set by the state or allowed to vary by company), policy forms, licensing requirements for title agents, financial reserve requirements for underwriters, and complaint handling procedures. The Consumer Financial Protection Bureau (CFPB) also has authority over settlement practices under RESPA. ALTA advocates for consistent, consumer-protective regulation. Source: NAIC, CFPB", cat: "insurance", source: "U.S. Treasury: Exploring Title Insurance", sourceUrl: "https://home.treasury.gov/news/featured-stories/exploring-title-insurance-consumer-protection-and-opportunities-for-potential-reforms" },

  // === MISC IMPORTANT ===
  { q: "What is a 1031 exchange?", a: "A 1031 exchange (named after IRS Code Section 1031) allows real estate investors to defer capital gains taxes by reinvesting sale proceeds into a 'like-kind' property. Strict rules apply: you must identify replacement property within 45 days and close within 180 days, use a qualified intermediary (not your regular closing agent), and the properties must be held for investment or business use (not your primary residence). Title insurance is required on the replacement property. This is an investment strategy — not applicable to typical homebuyers.", cat: "after", source: "IRS: Like-Kind Exchanges Under IRC Section 1031", sourceUrl: "https://www.irs.gov/businesses/small-businesses-self-employed/like-kind-exchanges-real-estate-tax-tips" },
  { q: "What is title insurance for a refinance?", a: "When you refinance your mortgage, your new lender will require a new lender's title insurance policy. This is because a new mortgage is being recorded and the lender needs protection against any title issues that may have arisen since your original purchase. The good news: many title companies offer a refinance rate (also called a reissue rate) that's significantly lower than the original premium — sometimes 40-60% less. Ask about this discount when refinancing.", cat: "insurance", source: "CFPB: When to Refinance", sourceUrl: "https://www.consumerfinance.gov/ask-cfpb/when-is-refinancing-your-mortgage-a-good-idea-en-158/" },
  { q: "What is an owner's title insurance enhanced policy?", a: "An enhanced (or extended) owner's policy provides broader coverage than the standard ALTA policy. Additional protections may include: post-policy coverage for certain risks (like building permit violations discovered after closing), inflation protection (coverage amount increases with property value), and coverage for certain zoning issues. Enhanced policies cost more but provide significantly stronger protection. Ask your title company about the difference between standard and enhanced coverage for your property.", cat: "insurance" },
  { q: "What questions should I ask before wiring money?", a: "Before wiring ANY funds for your closing: (1) Call your settlement agent at a number YOU already have — do NOT use numbers from emails, (2) Verify the bank name, routing number, and account number by phone, (3) Confirm the exact amount to wire, (4) Ask about the wire cutoff time (many banks stop processing after 3-4 PM), (5) Request that your settlement agent confirm receipt immediately after the wire processes, (6) Ask what to do if the wire doesn't arrive within the expected timeframe. If ANYTHING feels off, STOP and verify. Source: FBI IC3, ALTA", cat: "fraud", source: "FBI IC3: Wire Fraud Prevention", sourceUrl: "https://www.ic3.gov/" },
  { q: "What is the average timeline from offer to closing?", a: "Typical timelines: Conventional loan: 30-45 days. FHA loan: 45-60 days. VA loan: 45-60 days. Cash purchase: 14-30 days. New construction: varies by completion date. Key milestones: inspection within 7-10 days, appraisal within 2-3 weeks, title search within 1-2 weeks, Closing Disclosure 3 days before closing. Delays are common — budget extra time for: appraisal issues, title defects requiring resolution, lender underwriting conditions, and document corrections. Communicate frequently with your agent and lender.", cat: "closing", source: "CFPB: The Closing Process", sourceUrl: "https://www.consumerfinance.gov/owning-a-home/mortgage-closing/" },

  // === BATCH 5: PUSH TO 250 ===

  // More mortgage specifics
  { q: "What is an FHA 203(k) renovation loan?", a: "An FHA 203(k) loan lets you finance both the purchase of a home and the cost of renovations in a single mortgage. There are two types: the Standard 203(k) for major renovations over $35,000 (structural changes, room additions) and the Limited 203(k) for smaller projects under $35,000 (cosmetic updates, appliance replacement). Requirements include: 3.5% minimum down payment, 580+ credit score, the property must be at least one year old, and a HUD-approved 203(k) consultant is required for Standard loans. The loan amount is based on the projected value after renovations.", cat: "mortgage", source: "FHA.com: FHA 203(k) Loan", sourceUrl: "https://www.fha.com/fha_article?id=632" },
  { q: "What is a bridge loan?", a: "A bridge loan is a short-term loan (typically 6-12 months) that allows you to purchase a new home before selling your current one. It 'bridges' the gap by using the equity in your current home as collateral. Bridge loans have higher interest rates than traditional mortgages (typically 2-4% higher) and come with origination fees. They carry risk — if your current home doesn't sell quickly, you could be making payments on three obligations: the bridge loan, your current mortgage, and your new mortgage.", cat: "mortgage" },
  { q: "What is a construction-to-permanent loan?", a: "A construction-to-permanent loan (also called a single-close construction loan) finances the construction of a new home and then automatically converts into a permanent mortgage once construction is complete — with only one closing and one set of closing costs. During construction, you typically make interest-only payments on the funds disbursed. Once the home is complete, the loan converts to a standard 15- or 30-year mortgage. This is simpler and cheaper than getting separate construction and mortgage loans.", cat: "mortgage", source: "CFPB: Construction Loans", sourceUrl: "https://www.consumerfinance.gov/owning-a-home/" },
  { q: "What is a piggyback loan?", a: "A piggyback loan (or 80/10/10 loan) combines a primary mortgage for 80% of the home price with a second mortgage (home equity loan or HELOC) for 10%, and a 10% down payment. The primary benefit: you avoid PMI because your first mortgage is exactly 80% LTV. The second mortgage typically has a higher interest rate but is usually tax-deductible. Variations include 80/15/5 (5% down) and 80/20/0 (no down payment, rare). Do the math carefully — sometimes PMI is actually cheaper than the second mortgage's higher rate.", cat: "mortgage" },
  { q: "What is a reverse mortgage?", a: "A reverse mortgage (most commonly a Home Equity Conversion Mortgage or HECM) allows homeowners aged 62+ to convert home equity into cash — either as a lump sum, monthly payments, or a line of credit — without making monthly mortgage payments. The loan is repaid when the homeowner sells, moves out permanently, or passes away. The home must be your primary residence. Reverse mortgages are complex products with significant fees and can reduce the inheritance you leave to heirs. HUD requires counseling before you can apply.", cat: "mortgage", source: "CFPB: Reverse Mortgages", sourceUrl: "https://www.consumerfinance.gov/consumer-tools/reverse-mortgages/" },
  { q: "What is an assumable mortgage?", a: "An assumable mortgage allows a buyer to take over the seller's existing mortgage — including the interest rate, remaining term, and balance. This can be highly advantageous when current rates are higher than the seller's rate. FHA, VA, and USDA loans are generally assumable (with lender approval and qualification). Most conventional loans are NOT assumable due to 'due-on-sale' clauses. The buyer must qualify with the current lender and may need to cover the difference between the sale price and remaining loan balance with cash or a second mortgage.", cat: "mortgage", source: "CFPB: Assumable Mortgages", sourceUrl: "https://www.consumerfinance.gov/ask-cfpb/what-is-an-assumable-mortgage-en-240/" },

  // More closing process
  { q: "What is a table funding?", a: "Table funding is when a mortgage loan is closed in the name of a mortgage broker but funded by a wholesale lender that simultaneously purchases the loan. The broker handles the closing, but the funds come directly from the lender. This is the most common closing arrangement for broker-originated loans. From the borrower's perspective, it works the same as a direct lender closing — you sign the same documents and your title insurance is unaffected. The broker's compensation is disclosed on your Closing Disclosure.", cat: "closing", source: "CFPB: RESPA Definitions", sourceUrl: "https://www.consumerfinance.gov/compliance/compliance-resources/mortgage-resources/real-estate-settlement-procedures-act/" },
  { q: "What is a clear to close?", a: "Clear to close (CTC) is the final approval from your lender's underwriting department confirming that all loan conditions have been satisfied and the lender is ready to fund your mortgage. This typically happens 1-3 days before closing. Before CTC, the underwriter reviews: your credit (pulled again), employment verification, appraisal, title search results, insurance binder, and any requested documentation. Getting CTC is a major milestone — it means your loan is fully approved and closing can proceed as scheduled.", cat: "closing", source: "CFPB: Closing Process", sourceUrl: "https://www.consumerfinance.gov/owning-a-home/mortgage-closing/" },
  { q: "What is a notice of intent to proceed?", a: "After receiving your Loan Estimate, you must tell your lender you intend to proceed with the loan application. Until you do, the lender generally cannot charge you fees beyond a credit report fee. Once you provide intent to proceed (verbally or in writing), the lender can begin ordering services (appraisal, title search) and charging associated fees. This is not a commitment to close — you can still shop and change lenders, though you may lose fees already paid for services rendered.", cat: "closing", source: "CFPB: Loan Estimate Guide", sourceUrl: "https://www.consumerfinance.gov/owning-a-home/loan-estimate/" },

  // More insurance
  { q: "What is lender's title insurance?", a: "Lender's title insurance (also called a loan policy) protects the mortgage lender's investment against title defects, liens, and encumbrances. It covers the declining loan balance — not your equity. Almost all lenders require a loan policy as a condition of the mortgage. The premium is a one-time fee paid at closing. Important: the lender's policy does NOT protect you as the homeowner — that's what the separate owner's policy is for. When you pay off or refinance your mortgage, the lender's policy expires and a new one is needed.", cat: "insurance", source: "CFPB: What Is Lender's Title Insurance?", sourceUrl: "https://www.consumerfinance.gov/ask-cfpb/what-is-lenders-title-insurance-en-163/" },
  { q: "What is a title insurance underwriter?", a: "A title insurance underwriter is the company that actually assumes the risk and issues the title insurance policy. Think of the relationship like car insurance: title agents are like local insurance agents who sell policies and handle claims, while underwriters are like the insurance companies (State Farm, Allstate) that back the policies financially. Major national underwriters include First American, Fidelity National, Old Republic, and Stewart Title. When choosing a title company, knowing who underwrites their policies gives you confidence in the financial backing behind your coverage.", cat: "insurance", source: "CFPB: Title Insurance", sourceUrl: "https://www.consumerfinance.gov/ask-cfpb/what-is-owners-title-insurance-en-164/" },

  // More documents
  { q: "What is a title insurance policy jacket?", a: "The policy jacket is the standardized set of terms, conditions, and exclusions that accompany your title insurance policy. The jacket contains the legal 'fine print' — definitions, covered risks, exclusions from coverage, conditions for filing claims, and the company's obligations. The ALTA (American Land Title Association) publishes standardized policy jacket forms used by most title companies nationwide. Your specific coverage details (property, amount, exceptions) are in Schedules A and B, which are attached to the jacket.", cat: "documents" },
  { q: "What is a HUD-1 settlement statement?", a: "The HUD-1 was the standard closing document used before the CFPB's TRID rule took effect in 2015. It has been replaced by the Closing Disclosure for most residential mortgage transactions. However, the HUD-1 is still used for: reverse mortgages (HECMs), certain manufactured housing transactions, and transactions not involving a federally related mortgage (like cash purchases in some states). If you encounter a HUD-1, it serves the same purpose as a Closing Disclosure — itemizing all fees and fund flows.", cat: "documents", source: "CFPB: TRID Implementation", sourceUrl: "https://www.consumerfinance.gov/compliance/compliance-resources/mortgage-resources/tila-respa-integrated-disclosures/" },
  { q: "What is a mortgage note vs a deed of trust?", a: "These are two separate but related documents signed at closing. The mortgage note (promissory note) is your personal promise to repay the loan — it creates the debt obligation and specifies the terms (amount, rate, payment schedule, late fees). The deed of trust (or mortgage, depending on your state) is the document that gives the lender a security interest in your property — it creates the lien. If you default, the note establishes what you owe and the deed of trust gives the lender the right to foreclose. Both are needed — the note without security is just an unsecured promise; the deed of trust without a note has nothing to secure.", cat: "documents", source: "CFPB: What Is a Promissory Note?", sourceUrl: "https://www.consumerfinance.gov/ask-cfpb/what-is-a-promissory-note-en-2108/" },

  // More rights
  { q: "What is the Homeowners Protection Act?", a: "The Homeowners Protection Act (HPA) of 1998 establishes rules for the automatic termination and borrower-requested cancellation of Private Mortgage Insurance (PMI) on residential mortgages. Key provisions: you can REQUEST PMI cancellation when your loan balance reaches 80% of the original property value (must have good payment history). Your lender must AUTOMATICALLY cancel PMI when the balance reaches 78% of original value. For high-risk loans, automatic termination occurs at the midpoint of the loan term. These rules apply to borrower-paid PMI on loans closed after July 29, 1999.", cat: "rights", source: "CFPB: When Can I Remove PMI?", sourceUrl: "https://www.consumerfinance.gov/ask-cfpb/when-can-i-remove-private-mortgage-insurance-en-202/" },
  { q: "What is the Truth in Lending Act (TILA)?", a: "TILA is a federal law requiring lenders to clearly disclose the terms and costs of credit to consumers before they commit. For mortgages, TILA mandates disclosure of: the Annual Percentage Rate (APR), total finance charge, amount financed, total of payments, and payment schedule. TILA also provides the right of rescission for refinances (3-day cooling-off period). Combined with RESPA through the TRID rule, TILA ensures you receive standardized Loan Estimates and Closing Disclosures that make it easy to compare offers and understand your obligations.", cat: "rights", source: "CFPB: TILA-RESPA Integrated Disclosures", sourceUrl: "https://www.consumerfinance.gov/compliance/compliance-resources/mortgage-resources/tila-respa-integrated-disclosures/" },
  { q: "What are my rights if a title claim is filed against my property?", a: "If someone files a claim against your property's title and you have an owner's title insurance policy, your rights include: (1) the title company must investigate the claim at their expense, (2) they must provide legal defense — including hiring attorneys, paying court costs, and covering litigation expenses, (3) if the claim is valid and covered, they must pay your loss up to the policy amount, (4) you must promptly notify the company of any claim or potential claim, (5) you must cooperate with their investigation and defense. Your obligations and the company's obligations are detailed in the Conditions section of your policy.", cat: "rights" },
  { q: "Can I file a complaint about my title company?", a: "Yes. If you have concerns about your title company's practices, you have several options: (1) File a complaint with your state's department of insurance — they regulate title insurance companies and agents, (2) File a complaint with the CFPB if the issue involves RESPA violations, settlement practices, or disclosure requirements, (3) Contact ALTA if the company is a member — they have standards and a complaint process, (4) Consult a real estate attorney for legal remedies if you've suffered financial harm. Keep all documentation — correspondence, policies, closing documents, and a timeline of events.", cat: "rights", source: "CFPB: Submit a Complaint", sourceUrl: "https://www.consumerfinance.gov/complaint/" },

  // More after closing
  { q: "What is a mortgage modification?", a: "A mortgage modification is a permanent change to the terms of your existing loan — typically to make payments more affordable. Modifications can include: reducing the interest rate, extending the loan term (from 30 to 40 years), switching from adjustable to fixed rate, reducing the principal balance (rare), or capitalizing delinquent amounts. Modifications are typically available to borrowers in financial hardship who can't afford their current payments. Contact your servicer early if you're struggling — they're required to evaluate you for loss mitigation options before foreclosure.", cat: "after", source: "CFPB: Trouble Paying Mortgage", sourceUrl: "https://www.consumerfinance.gov/housing/housing-insecurity/help-for-homeowners/trouble-paying-mortgage/" },
  { q: "What is forbearance?", a: "Mortgage forbearance is a temporary agreement with your servicer to reduce or suspend your mortgage payments during a period of financial hardship — such as job loss, medical emergency, or natural disaster. Forbearance is NOT forgiveness — you must repay the missed amounts later through a repayment plan, modification, or lump sum. Contact your servicer as soon as you anticipate difficulty making payments. Forbearance options vary by loan type: FHA, VA, and USDA loans have specific forbearance programs. During forbearance, your servicer cannot charge late fees or report you as delinquent (if you're current when forbearance begins).", cat: "after", source: "CFPB: Mortgage Forbearance", sourceUrl: "https://www.consumerfinance.gov/housing/housing-insecurity/help-for-homeowners/trouble-paying-mortgage/" },
  { q: "What is a home equity loan vs a HELOC?", a: "Both let you borrow against your home equity, but they work differently. A home equity loan is a lump-sum loan with a fixed interest rate and fixed monthly payments — like a second mortgage. A HELOC (Home Equity Line of Credit) is a revolving credit line with a variable rate — you draw money as needed during the draw period (typically 10 years), then repay during the repayment period (typically 20 years). Home equity loans are better for one-time expenses (renovation, debt consolidation). HELOCs are better for ongoing or unpredictable expenses. Both use your home as collateral — if you default, the lender can foreclose.", cat: "after", source: "CFPB: Home Equity Loans and HELOCs", sourceUrl: "https://www.consumerfinance.gov/ask-cfpb/what-is-a-home-equity-loan-en-106/" },
  { q: "What is private transfer fee?", a: "A private transfer fee (also called a reconveyance fee or capital recovery fee) is a charge imposed by a homeowner association, developer, or previous owner that must be paid every time the property is sold — typically 1% of the sale price. These fees are recorded against the property and 'run with the land' — meaning every future buyer must pay them. They're controversial and banned or restricted in many states. Your title search should reveal any private transfer fee obligations. Ask your title company specifically about these before closing.", cat: "costs" },
  { q: "What is a seller disclosure?", a: "A seller disclosure (also called a property condition disclosure or transfer disclosure statement) is a document where the seller discloses known material defects and conditions of the property. Requirements vary by state — most states require some form of disclosure, but the scope differs. Common items disclosed: known foundation issues, water damage history, pest infestations, environmental hazards (lead paint, asbestos), neighborhood nuisances, HOA disputes, insurance claims history, and deaths on the property (required in some states). Review this carefully before your inspection and ask questions about anything concerning.", cat: "documents" },
  { q: "What is a home's chain of custody?", a: "In real estate, chain of custody most commonly refers to the chain of title — the documented history of property ownership from the original government land grant through every subsequent transfer to the present owner. Each transfer should be recorded with the county through a deed. A complete, unbroken chain of custody/title is essential for clear ownership. If any link is missing, defective, or questionable (forged deed, improper transfer, missing heir), it creates a 'cloud on title' that must be resolved before you can get title insurance and close on the property.", cat: "basics", source: "CFPB: Owner's Title Insurance", sourceUrl: "https://www.consumerfinance.gov/ask-cfpb/what-is-owners-title-insurance-en-164/" },

  // More fraud
  { q: "What is social engineering in real estate fraud?", a: "Social engineering is the manipulation of people into performing actions or divulging confidential information. In real estate, criminals use social engineering to: impersonate title company employees via email or phone, create urgency around wire transfers ('the closing will be delayed if you don't wire today'), trick employees into changing wire instructions, and use publicly available information (MLS listings, social media) to identify pending transactions and target buyers. Defense: verify everything through a second channel, be suspicious of urgency, and never provide financial information to someone who contacted you first.", cat: "fraud", source: "FBI IC3: Business Email Compromise", sourceUrl: "https://www.ic3.gov/" },
  { q: "What is phishing in real estate?", a: "Phishing is a type of social engineering where criminals send fraudulent emails designed to look like they come from legitimate companies — your lender, real estate agent, or title company — to trick you into clicking malicious links, providing login credentials, or following fake wire instructions. In real estate, phishing is the entry point for most wire fraud schemes. Red flags: unexpected emails about wire changes, slight misspellings in the sender's domain, generic greetings instead of your name, urgency language, and requests to click links rather than calling. Always verify by calling a known number.", cat: "fraud", source: "CFPB: Protecting Your Money", sourceUrl: "https://www.consumerfinance.gov/consumer-tools/fraud/" },

  // More inspections
  { q: "What is a wind mitigation inspection?", a: "A wind mitigation inspection evaluates features of your home that reduce damage from windstorms — roof shape and covering, roof deck attachment, roof-to-wall connections, opening protection (hurricane shutters, impact windows), and secondary water resistance. This inspection is particularly important in hurricane-prone states like Florida, where it can significantly reduce your homeowner's insurance premium — sometimes by 40-60%. Cost: $75-150. Florida law requires insurance companies to provide discounts for verified wind mitigation features. Not applicable in all states.", cat: "inspection" },
  { q: "What is the difference between a home inspection and an appraisal?", a: "A home inspection evaluates the property's physical condition — structure, systems, safety. It's ordered by the buyer, costs $300-500, and results in a detailed report of defects and maintenance needs. An appraisal determines the property's market value — it's ordered by the lender, costs $300-600, and results in a value opinion. The inspector works for you; the appraiser works for the lender. A home can appraise at full value but still have significant physical problems, or pass inspection but appraise lower than the purchase price. You need both.", cat: "inspection", source: "CFPB: Home Appraisals", sourceUrl: "https://www.consumerfinance.gov/ask-cfpb/what-is-a-home-appraisal-en-2086/" },

  // More costs
  { q: "What is a loan origination fee?", a: "The loan origination fee is the lender's charge for processing, evaluating, and approving your mortgage application. It typically ranges from 0.5% to 1% of the loan amount — for a $350,000 loan, that's $1,750 to $3,500. This is a zero-tolerance fee under TRID, meaning it cannot increase from your Loan Estimate to your Closing Disclosure. The origination fee is negotiable — compare across lenders. Some offer 'no origination fee' loans but compensate with higher interest rates. Always compare the total cost (APR) rather than individual fees.", cat: "costs", source: "CFPB: Understand Loan Costs", sourceUrl: "https://www.consumerfinance.gov/owning-a-home/close/understand-closing-costs/" },
  { q: "What is a credit report fee?", a: "The credit report fee covers the cost of your lender pulling your credit history from the three major bureaus (Equifax, Experian, TransUnion). This is typically one of the few fees a lender can charge before you provide intent to proceed — usually $30-60 for a tri-merge report. Your credit score significantly impacts your interest rate: a 740+ score gets the best conventional rates, while lower scores result in higher rates and potentially higher PMI costs. You can check your own credit free at annualcreditreport.com without affecting your score.", cat: "costs", source: "FTC: Free Credit Reports", sourceUrl: "https://www.consumer.ftc.gov/articles/free-credit-reports" },
  { q: "What is a flood certification?", a: "A flood certification (also called a flood determination) is a document that identifies whether a property is located in a FEMA-designated flood zone. Cost: $15-25. If your property IS in a flood zone, your lender will require flood insurance in addition to standard homeowner's insurance. Flood insurance is available through the National Flood Insurance Program (NFIP) or private insurers. Annual premiums range from a few hundred to several thousand dollars depending on the zone and coverage. Check flood maps at msc.fema.gov before making an offer.", cat: "costs", source: "FEMA: Flood Map Service Center", sourceUrl: "https://msc.fema.gov/" },

  // More basics
  { q: "What is a warranty deed?", a: "A warranty deed (also called a general warranty deed) is the strongest form of property deed, providing the buyer with the most protection. The seller (grantor) guarantees: they have legal ownership and the right to sell, the property is free from all encumbrances except those disclosed, and they will defend the buyer's title against any claims — even claims arising from before the seller owned the property. This is the standard deed type for most residential real estate purchases. Always insist on a warranty deed when buying a home — never accept a quitclaim deed for a purchase.", cat: "basics" },
  { q: "What is a special warranty deed?", a: "A special warranty deed provides a more limited guarantee than a general warranty deed. The seller only warrants the title against claims arising DURING their period of ownership — not before. If a defect existed before the seller acquired the property, they're not responsible. Special warranty deeds are more common in: commercial transactions, bank-owned (REO) properties, and some new construction sales. When buying with a special warranty deed, owner's title insurance becomes even more critical because the seller's warranty is limited.", cat: "basics" },
  { q: "What is eminent domain?", a: "Eminent domain is the government's constitutional power to take private property for public use — but only with 'just compensation' to the owner. Examples include building highways, schools, utilities, and public facilities. The government must prove the taking serves a legitimate public purpose and must pay fair market value. Title insurance generally doesn't cover eminent domain (it's a government regulation exclusion), but it may cover issues like failure to receive proper compensation or procedural violations in the condemnation process.", cat: "basics" },
  { q: "What is a mechanic's lien?", a: "A mechanic's lien is a legal claim filed by a contractor, subcontractor, or material supplier who performed work on a property but wasn't paid. The lien attaches to the property — not the person who ordered the work — meaning you could be liable for the previous owner's unpaid bills. This is one of the most common title issues found during searches. Title insurance protects against mechanic's liens that existed before your purchase but weren't discovered during the search. Before closing, your title company should verify all contractors have been paid or have signed lien waivers.", cat: "basics" },

  // More after
  { q: "What is a quitclaim deed and when would I need one?", a: "A quitclaim deed transfers whatever ownership interest the grantor has — with NO warranties or guarantees. Common uses AFTER closing: adding a spouse to the deed after marriage, removing an ex-spouse after divorce, transferring property to a trust for estate planning, correcting a misspelled name on the deed, or clearing a cloud on title. Quitclaim deeds should NEVER be used for a purchase transaction (always use a warranty deed). When recording a quitclaim, notify your title insurance company and mortgage servicer — some loans have due-on-sale clauses that could be triggered.", cat: "after" },
  { q: "What happens to my title insurance if I add someone to the deed?", a: "Adding someone to your deed (via quitclaim or other transfer) may affect your owner's title insurance coverage. Most standard ALTA policies continue to cover the original named insured even after adding someone to the deed — but the coverage may not extend to the added person. Contact your title insurance company before making any changes to find out: (1) whether your existing coverage is affected, (2) whether the new person needs their own policy, and (3) whether an endorsement is available to extend coverage. Don't assume — verify.", cat: "after" },

  // Essential knowledge
  { q: "What are the top 10 things every buyer should know before closing?", a: "(1) Read your Closing Disclosure line by line — compare to your Loan Estimate. (2) NEVER wire money based on email instructions — always call to verify. (3) Get owner's title insurance — it protects your investment for life. (4) Attend your home inspection personally. (5) You have the RIGHT to choose your own title company (RESPA). (6) Get pre-approved by 2-3 lenders and compare APRs, not just rates. (7) Don't make major financial changes after pre-approval. (8) Budget 2-5% of the home price for closing costs ON TOP of your down payment. (9) Understand your contingencies and their deadlines. (10) Keep all closing documents permanently — you'll need them for taxes, claims, and when you sell.", cat: "closing", source: "CFPB: Buying a House Guide", sourceUrl: "https://www.consumerfinance.gov/owning-a-home/" },

  // === FINAL PUSH TO 250 ===

  // Specific scenario questions buyers ask
  { q: "What if I'm buying a home with someone I'm not married to?", a: "Unmarried co-buyers face unique legal considerations. Key decisions: how to take title (joint tenants with right of survivorship, or tenants in common — which affects what happens if one partner dies), what happens if one person wants to sell and the other doesn't, how to split expenses and equity if you separate, and whether to create a co-ownership agreement (strongly recommended). Unlike married couples, unmarried co-buyers have no default legal protections. Have a real estate attorney draft a co-ownership agreement before closing that covers: ownership percentages, expense responsibilities, exit procedures, buyout terms, and dispute resolution.", cat: "closing" },
  { q: "Can I buy a house while self-employed?", a: "Yes, but it requires more documentation. Most lenders want to see at least 2 years of self-employment history. You'll need: 2 years of personal and business tax returns, year-to-date profit and loss statement, business license or DBA documentation, and possibly a CPA letter. Lenders use your NET income (after deductions) — not gross revenue — which is often much lower than what W-2 employees show. This can limit your borrowing power. Tips: minimize tax deductions in the 1-2 years before applying (you'll pay more tax but qualify for a larger loan), maintain clean business accounts, and consider FHA which may be more flexible for self-employed borrowers.", cat: "mortgage", source: "CFPB: Prepare for Homeownership", sourceUrl: "https://www.consumerfinance.gov/owning-a-home/prepare/" },
  { q: "What if I'm relocating for work — can I close remotely?", a: "Yes — several closing options accommodate relocation. Mail-away closing: documents are sent to you via courier, a mobile notary meets you at your location ($150-300 extra). Remote Online Notarization (RON): fully digital closing via live video — available in most states but requires your lender and title company to support it. Power of attorney: someone you designate signs on your behalf (must be pre-approved by your lender). Plan ahead — notify your settlement agent about your situation at least 2-3 weeks before closing. For military relocations, VA loans have specific accommodations.", cat: "closing", source: "CFPB: Closing Process", sourceUrl: "https://www.consumerfinance.gov/owning-a-home/mortgage-closing/" },
  { q: "What happens if the seller hasn't moved out by closing day?", a: "If the seller hasn't vacated by closing, you have options: (1) Delay closing until they move — but this may affect your rate lock and moving timeline. (2) Use a post-occupancy agreement (rent-back) — the seller pays you rent for a specified period while they transition out, with a clear deadline and penalties for exceeding it. (3) Hold funds in escrow — a portion of the seller's proceeds is held until they vacate, providing financial incentive. (4) Refuse to close — if the purchase agreement requires vacant possession and the seller can't deliver, you may be able to cancel. Get the agreement in writing before closing.", cat: "closing" },
  { q: "What if I find the house has problems AFTER closing?", a: "Options depend on the nature of the problem: (1) Title issues (unknown liens, ownership claims) — file a claim on your owner's title insurance policy. (2) Structural/physical defects the seller knew about but didn't disclose — you may have legal recourse under your state's disclosure laws (consult a real estate attorney). (3) Defects nobody knew about — typically the buyer's responsibility, which is why inspections are critical. (4) Defects the inspector should have caught — the inspector may have professional liability insurance. (5) Systems that fail within warranty — contact the builder (new construction) or your home warranty company. Document everything and act promptly.", cat: "after" },

  // Tax and financial
  { q: "What is the SALT deduction cap and how does it affect me?", a: "The State and Local Tax (SALT) deduction is capped at $10,000 per year ($5,000 if married filing separately) under the Tax Cuts and Jobs Act. This cap combines: state income taxes (or sales taxes), local income taxes, AND property taxes into a single $10,000 limit. In high-tax states (New York, New Jersey, California, Connecticut), many homeowners' property taxes ALONE exceed $10,000 — meaning they get no additional deduction for state income taxes. This cap significantly impacts the after-tax cost of homeownership in high-tax areas. Check with a tax professional for your specific situation.", cat: "costs", source: "IRS: State and Local Tax Deduction", sourceUrl: "https://www.irs.gov/newsroom/tax-reform-basics-for-individuals-and-families" },
  { q: "What is a gift letter for a down payment?", a: "If any part of your down payment comes from a family member or other source (not your own savings), your lender will require a gift letter. The letter must state: the donor's name and relationship to you, the gift amount, the property address, and a statement that the money is a GIFT with no expectation of repayment. The donor may also need to provide bank statements showing the source of the funds. Gift rules vary by loan type: Conventional and FHA allow gifts from family members; FHA also allows gifts from employers, unions, and down payment assistance programs; VA allows gifts from anyone.", cat: "mortgage", source: "CFPB: Understanding Down Payments", sourceUrl: "https://www.consumerfinance.gov/owning-a-home/explore/decide-how-much/" },
  { q: "What is owner financing or seller financing?", a: "Owner financing (seller financing) is when the seller acts as the lender — you make payments directly to the seller instead of a bank. This is sometimes used when the buyer can't qualify for traditional financing, or when both parties want to avoid the delays and costs of bank underwriting. Terms are negotiable: interest rate, loan term, down payment, and balloon payment (if any). Owner-financed transactions still require title insurance — in fact, it's even more important because there's no institutional lender reviewing the title. A real estate attorney should draft the promissory note and deed of trust.", cat: "mortgage" },

  // More title/closing specifics
  { q: "What is a title curative?", a: "Title curative (also called curative work or clearing title) is the process of resolving defects discovered during the title search. Common curatives include: obtaining a release for an old mortgage that was paid off but never formally released, getting signatures from missing heirs, correcting spelling errors on recorded documents, obtaining affidavits to clarify gaps in the chain of title, and resolving outstanding liens or judgments. This is one of the most valuable services title professionals provide — they fix problems you didn't know existed before they affect your ownership.", cat: "basics" },
  { q: "What is an abstract continuation?", a: "In states that use abstract-based title systems (primarily in the Midwest and parts of the South), an abstract continuation is an update to the existing abstract of title to cover the period since the last transaction. Rather than starting a new search from scratch, the title examiner examines only the documents recorded since the abstract was last updated. The continuation is then added to the physical abstract book. In states using title plants or computerized systems, the concept of continuation still applies — the search picks up where the last examination left off.", cat: "basics" },
  { q: "What is a closing protection letter?", a: "A closing protection letter (CPL) is a document issued by the title insurance underwriter to the lender, providing limited protection against losses caused by the closing agent's fraud or dishonesty — such as stealing closing funds or failing to follow lender instructions. The CPL protects the LENDER, not the buyer. It covers specific scenarios like: the closing agent absconding with funds, failing to record the deed or mortgage, or issuing fraudulent title policies. CPLs are standard in most transactions and are typically requested by the lender.", cat: "insurance" },
  { q: "What is a title affidavit?", a: "A title affidavit is a sworn statement signed by the seller (or buyer) at closing that addresses specific title-related matters. Common affidavits include: seller's affidavit (no additional liens, no bankruptcies, no unpaid contractors), name affidavit (confirming the seller is the same person named on the deed, especially if names have changed), marital status affidavit (confirming whether the seller's spouse has any interest in the property), and gap affidavit (covering the period between the last title update and the closing date). These provide additional assurance and support the title insurance policy.", cat: "documents" },

  // More practical buyer advice
  { q: "How do I choose a real estate agent?", a: "Interview at least 2-3 agents before choosing. Key questions: How many transactions have you closed in this area in the past year? Do you work primarily with buyers or sellers? What is your availability and preferred communication method? Can you provide references from recent buyer clients? Are you a Realtor (NAR member bound by Code of Ethics)? What happens if I'm unhappy with your service — can I terminate the agreement? A good buyer's agent should: know the local market deeply, be responsive to your questions, explain each step clearly, and advocate for your interests in negotiations. Trust your instincts.", cat: "closing" },
  { q: "What is the difference between pre-approved and pre-qualified?", a: "Pre-qualification is an informal estimate of how much you might borrow — based on self-reported financial information, with no verification. It takes minutes and carries little weight with sellers. Pre-approval is a formal process: the lender verifies your income, assets, debts, employment, and credit history, then issues a conditional commitment for a specific loan amount. Pre-approval typically takes 1-3 days and requires documentation (pay stubs, tax returns, bank statements). Sellers strongly prefer pre-approved buyers because it demonstrates you're both serious and financially qualified.", cat: "mortgage", source: "CFPB: Get Pre-Approved", sourceUrl: "https://www.consumerfinance.gov/owning-a-home/prepare/get-pre-approved/" },
  { q: "What is a buyer's agent agreement?", a: "A buyer's agent agreement is a contract between you and your real estate agent formalizing the agency relationship. It specifies: the duration of the agreement, the geographic area covered, the agent's compensation (commission rate or flat fee), the services the agent will provide, your obligations as the buyer, and how the agreement can be terminated. Since NAR's 2024 settlement, buyer agent compensation practices have changed — buyers may need to negotiate and potentially pay their agent directly, rather than the seller automatically paying the buyer's agent commission.", cat: "closing" },
  { q: "What is an as-is sale?", a: "In an 'as-is' sale, the seller is offering the property in its current condition and is unwilling to make repairs or reduce the price based on defects. However, 'as-is' does NOT mean: you can't get an inspection (you absolutely should), the seller doesn't have to disclose known defects (they still must in most states), or that you can't walk away (your inspection contingency still protects you). 'As-is' simply means the seller won't negotiate repairs. You still have the right to inspect, evaluate, and decide whether to proceed. Common in estate sales, foreclosures, and investor flips.", cat: "closing" },
  { q: "What is a home's assessed value vs market value?", a: "Assessed value is the value assigned by your county tax assessor for property tax purposes. Market value is what a willing buyer would pay and a willing seller would accept in an open market. These are often different: assessed values may be higher or lower than market value depending on when the last assessment occurred, assessment methodology, and local laws. Some states assess at 100% of market value; others use a percentage (e.g., 70%). Your property taxes are based on assessed value, not market value. If you believe your assessment is too high, you can appeal.", cat: "costs", source: "Tax Foundation: Property Tax Data", sourceUrl: "https://taxfoundation.org/data/all/state/property-taxes-by-state-county/" },

  // More insurance specifics
  { q: "What happens if my title company goes out of business?", a: "Your title insurance policy is backed by the underwriter — not the local title agent. If the agent goes out of business, your coverage continues unchanged because the underwriter (First American, Fidelity, Old Republic, Stewart, etc.) is the entity that actually assumes the risk. For claims, you would contact the underwriter directly. If the underwriter itself faces financial difficulty, state guaranty funds provide a safety net (similar to FDIC for banks). This is why it matters who underwrites your policy — choose a financially strong underwriter.", cat: "insurance" },
  { q: "Can I transfer my title insurance to a new owner?", a: "No — owner's title insurance policies are non-transferable. Your policy protects only you (and your heirs) for the time period you own the property. When you sell, the buyer gets their own new policy. However, some title companies offer a 'reissue rate' — a discounted premium for the new buyer because a recent title search already exists on the property. If you're selling, let the buyer know a recent policy exists — it may save them money. The lender's policy similarly expires when the loan is paid off or refinanced.", cat: "insurance" },

  // Final essential knowledge
  { q: "What is the single biggest risk for homebuyers today?", a: "Wire fraud. While title defects, inspection issues, and financing problems are all real risks, wire fraud is the most immediately devastating — and the most preventable. In 2025, $275.1 million was stolen from real estate transactions through fraudulent wire instructions. The average loss per incident is approximately $150,000 — often the buyer's entire down payment and closing costs, gone in minutes. The #1 rule: NEVER wire money based solely on email instructions. Always verify wiring details by phone using a number you already have on file. If something feels off, stop and call.", cat: "fraud", source: "CertifID: 2026 State of Wire Fraud Report", sourceUrl: "https://www.certifid.com/state-of-wire-fraud" },
  { q: "What makes a good title company?", a: "Look for: (1) ALTA membership — indicates commitment to industry standards. (2) ALTA Best Practices certification — the gold standard for operations and security. (3) Strong wire fraud prevention — wire verification technology (CertifID, Closinglock), MFA on all systems, encrypted portals. (4) Clear communication — they explain documents in plain language and are responsive to questions. (5) Transparent fees — provides itemized estimates in writing immediately. (6) Financial strength of the underwriter — look for a nationally recognized underwriter backing their policies. (7) Positive reviews and agent referrals. (8) Proper licensing and E&O insurance. Your title company protects the largest investment of your life — choose carefully.", cat: "basics" },
  { q: "What is the most important document I'll sign at closing?", a: "While every document matters, the Closing Disclosure is arguably the most important because it's your final opportunity to verify that every term, fee, and cost matches what you agreed to. Other critical documents: the promissory note (your legal promise to repay — specifying the exact terms of your obligation) and the deed of trust (giving the lender foreclosure rights). But the Closing Disclosure is where errors are most likely to occur and where catching them saves you the most money. If something on the Closing Disclosure doesn't match your Loan Estimate, ask about it BEFORE you sign anything else.", cat: "documents", source: "CFPB: Review Your Closing Disclosure", sourceUrl: "https://www.consumerfinance.gov/owning-a-home/closing-disclosure/" },

  // === FINAL 22 TO HIT 250 ===
  { q: "What is a title insurance premium refund?", a: "In most cases, title insurance premiums are non-refundable — once the policy is issued, the premium has been earned. However, if the transaction falls through BEFORE the policy is issued (before closing and recording), you may be eligible for a partial refund of the premium, minus fees for the title search and examination work already performed. Each company and state has different refund policies. If your transaction cancels, ask your title company about their cancellation and refund policy immediately.", cat: "insurance" },
  { q: "What is a title insurance reissue rate?", a: "A reissue rate (also called a refinance rate or substitute rate) is a discounted title insurance premium available when a prior policy exists on the property. If the previous owner had title insurance within a certain timeframe (typically 3-10 years, varies by state), the new policy may cost 20-40% less because the title company can build on the previous search rather than starting from scratch. Always ask about reissue rates — not all companies volunteer this discount.", cat: "insurance" },
  { q: "What is an owner's affidavit?", a: "An owner's affidavit (also called a seller's affidavit or title affidavit) is a sworn statement the seller signs at or before closing attesting to specific facts about the property: that there are no undisclosed liens or encumbrances, no pending lawsuits, no unpaid contractors or materialmen, no boundary disputes, and no additional parties with ownership claims. This document helps the title company close the 'gap' between the last title update and the closing date and supports the issuance of the title insurance policy.", cat: "documents" },
  { q: "What is gap coverage in title insurance?", a: "The 'gap' is the period between the last title search update and the recording of your deed after closing. During this gap, new liens, judgments, or other claims could be filed against the property. Gap coverage protects you against anything that gets recorded during this period. Most title companies include gap coverage in their standard policies, but it's worth confirming. Without gap coverage, a lien filed between your search date and recording date could affect your title.", cat: "insurance" },
  { q: "What is a lis pendens?", a: "A lis pendens (Latin for 'pending lawsuit') is a legal notice filed in public records indicating that a lawsuit has been filed involving the property. It serves as a warning to potential buyers that the property is the subject of litigation. Lis pendens are discovered during the title search and must be resolved or accepted before closing. Common causes: foreclosure proceedings, divorce disputes, contractor liens, and boundary disagreements. Title insurance may or may not cover the underlying claim depending on the nature of the lawsuit.", cat: "basics" },
  { q: "What is the difference between a mortgage and a deed of trust?", a: "Both serve the same purpose — giving the lender a security interest in your property — but they differ in the foreclosure process. Mortgage states require judicial foreclosure (through the courts), which is slower and gives the borrower more protection. Deed of trust states allow non-judicial foreclosure (through a trustee), which is faster. Some states use both depending on the circumstances. The choice of instrument is determined by state law, not by you or your lender. From a practical standpoint, your daily experience as a homeowner is the same regardless of which is used.", cat: "basics" },
  { q: "What is an escrow analysis?", a: "An escrow analysis is an annual review your mortgage servicer performs to ensure your escrow account has enough funds to pay your property taxes and homeowner's insurance when they come due. If the analysis reveals a shortage (not enough money), your monthly payment may increase. If there's a surplus (too much money), you may receive a refund. Your servicer is required to provide this analysis annually and must notify you of any payment changes at least 30 days in advance. Shortages can be paid as a lump sum or spread over 12 months.", cat: "after", source: "CFPB: What Is an Escrow Analysis?", sourceUrl: "https://www.consumerfinance.gov/ask-cfpb/what-is-an-escrow-or-impound-account-en-140/" },
  { q: "What is a subordination agreement?", a: "A subordination agreement changes the priority of liens on a property. Lien priority is typically determined by recording date — 'first in time, first in right.' A subordination agreement allows a junior lien to maintain its position when a senior lien is refinanced. For example, if you have a first mortgage and a HELOC, and you refinance the first mortgage, the HELOC lender may need to sign a subordination agreement to remain in second position. Without subordination, the refinanced loan would drop behind the HELOC in priority, which most lenders won't accept.", cat: "basics" },
  { q: "What is title insurance in a refinance?", a: "When you refinance your mortgage, your new lender requires a new lender's title insurance policy. This is because a new mortgage is being recorded and the lender needs protection against any title issues that arose since your original purchase — new liens, judgments, or other encumbrances. The good news: many title companies offer a refinance rate (reissue rate) that's significantly discounted from the original premium — sometimes 40-60% less. Always ask about this discount. Your existing owner's policy remains in effect and does not need to be repurchased.", cat: "insurance", source: "CFPB: When to Refinance", sourceUrl: "https://www.consumerfinance.gov/ask-cfpb/when-is-refinancing-your-mortgage-a-good-idea-en-158/" },
  { q: "What is the difference between a title agent and a title underwriter?", a: "Title agents are local companies that conduct title searches, facilitate closings, and issue policies on behalf of underwriters — similar to how a local insurance agent sells policies for a larger insurance company. Title underwriters are the companies that assume the financial risk and back the policies — like First American, Fidelity National, Old Republic, Stewart, Westcor, and WFG. When you buy title insurance, you're working with the agent but your policy is backed by the underwriter's financial reserves. The underwriter's financial strength matters — it determines whether they can pay large claims.", cat: "basics" },
  { q: "What is a satisfaction of mortgage?", a: "A satisfaction of mortgage (also called a mortgage release, reconveyance, or discharge) is a document recorded with the county after you pay off your mortgage in full. It releases the lender's lien from your property's title, showing the world that the debt is satisfied and the lender no longer has a security interest. Your lender is required by law to record this within a specific timeframe after payoff (varies by state, typically 30-90 days). If your lender fails to record it, it can create a cloud on your title that must be resolved before you can sell or refinance.", cat: "after" },
  { q: "What are my rights during the inspection contingency period?", a: "During the inspection contingency period (typically 7-10 days after the accepted offer): (1) You have the right to hire any licensed inspector you choose — not one recommended by the seller. (2) You have the right to inspect all accessible areas of the property. (3) You can order additional specialty inspections (radon, sewer, termite). (4) Based on the results, you can: accept the property as-is, request repairs, negotiate a price reduction or credit, or terminate the contract and get your earnest money back. (5) If you terminate within the contingency period for inspection-related reasons, you are entitled to a full refund of your earnest money deposit.", cat: "rights" },
  { q: "What is the cooling-off period for homebuyers?", a: "Unlike many consumer transactions, there is generally NO cooling-off period or right of rescission for a home PURCHASE mortgage. Once you sign at closing, you're committed. The 3-day right of rescission under TILA applies only to REFINANCES of your primary residence, not purchases. This is why the CFPB requires you to receive your Closing Disclosure at least 3 business days BEFORE closing — that's your review period. Use those 3 days to review every number, compare to your Loan Estimate, and ask questions. Once you sign at the closing table, there's generally no turning back.", cat: "rights", source: "CFPB: Right of Rescission", sourceUrl: "https://www.consumerfinance.gov/ask-cfpb/for-a-home-equity-loan-or-home-equity-line-of-credit-what-is-the-right-of-rescission-en-137/" },
  { q: "What is a dual agent and should I use one?", a: "A dual agent represents BOTH the buyer and the seller in the same transaction. While legal in most states (with disclosure and consent), dual agency creates an inherent conflict of interest — the agent can't fully advocate for either party's best interests simultaneously. Many buyer advocates recommend against dual agency, especially for first-time buyers. If you're working with a dual agent, understand: they cannot advise you on what price to offer, they cannot share either party's confidential information with the other, and you may not get the same level of negotiation support as with a dedicated buyer's agent.", cat: "closing" },
  { q: "What should I do if I receive an email about changed wiring instructions?", a: "STOP. Do NOT follow the instructions. Do NOT click any links. Do NOT reply to the email. Instead: (1) Call your title company or settlement agent at a phone number you ALREADY have on file — not a number from the email. (2) Forward (don't reply to) the suspicious email to your agent and settlement company. (3) If you already wired money to a potentially fraudulent account, contact your bank immediately to request a wire recall, then file a report at ic3.gov. The email may look identical to a real one — criminals can spoof domains, copy logos, and mimic writing styles. The ONLY safe verification is a phone call to a known number.", cat: "fraud", source: "FBI IC3: Wire Fraud Prevention", sourceUrl: "https://www.ic3.gov/" },
  { q: "What is a property condition disclosure?", a: "A property condition disclosure (also called a seller disclosure statement or transfer disclosure) is a form the seller completes disclosing known material defects and conditions of the property. Disclosure requirements vary by state but commonly cover: structural issues, water damage, pest infestations, environmental hazards (lead paint in pre-1978 homes, asbestos, radon), heating/cooling system condition, plumbing and electrical issues, roof age and condition, neighborhood nuisances, and insurance claim history. Federal law requires disclosure of known lead-based paint hazards in homes built before 1978.", cat: "documents", source: "EPA: Lead-Based Paint Disclosure", sourceUrl: "https://www.epa.gov/lead/real-estate-disclosures-about-potential-lead-hazards" },
  { q: "What is owner's title insurance enhanced coverage?", a: "An enhanced (or extended coverage) owner's policy provides broader protection than the standard ALTA policy. Typical additional coverages include: post-policy forgery protection, building permit violations discovered after closing, encroachment by neighbors' structures, living trust coverage, boundary wall or fence coverage, map inconsistency coverage, and inflation protection (coverage amount increases automatically with property value up to 150% of the original amount over 5 years). Enhanced policies cost 10-20% more than standard but provide significantly stronger protection. Ask your title company to compare standard vs enhanced coverage.", cat: "insurance" },
  { q: "How do I prepare for my first home closing?", a: "Preparation checklist: (1) Review your Closing Disclosure carefully as soon as you receive it (3+ days before closing). (2) Compare every line to your Loan Estimate — question any changes. (3) Verify wire transfer instructions BY PHONE using a known number. (4) Complete your final walk-through — check all negotiated repairs. (5) Gather documents: two forms of photo ID, proof of homeowner's insurance, certified check or wire confirmation. (6) Confirm the closing date, time, location, and who needs to attend. (7) Know your questions — write them down and bring the list. (8) Allow 60-90 minutes for the appointment. (9) Don't plan to move in immediately — allow buffer time. (10) Bring a phone for photos of all signed documents.", cat: "closing", source: "CFPB: Prepare for Closing", sourceUrl: "https://www.consumerfinance.gov/owning-a-home/close/" },
  { q: "What is the number one question first-time buyers should ask their title company?", a: "Ask: 'What is your process for protecting my wire transfer?' This single question reveals more about a title company's professionalism than any other. A good company will immediately explain: they use wire verification technology (CertifID, Closinglock), they never send wire instructions solely by email, they have a documented phone verification process, and their staff is trained on fraud prevention. A company that gives a vague answer or seems surprised by the question may not have adequate fraud protection — and that puts your money at risk. Wire fraud is the #1 threat to homebuyers. Make sure your title company takes it seriously.", cat: "fraud", source: "CertifID: Wire Fraud Prevention", sourceUrl: "https://www.certifid.com/article/how-to-prevent-wire-fraud" },
  { q: "Where can I learn more about the home closing process?", a: "Trusted resources for homebuyer education: (1) CFPB's Owning a Home guide (consumerfinance.gov/owning-a-home) — the most comprehensive free federal resource. (2) HomeClosing101.org — ALTA's educational initiative (this site). (3) Fannie Mae HomeView — free online homebuyer course with certificate. (4) Freddie Mac CreditSmart — free financial education. (5) HUD-approved housing counselors — free or low-cost personalized guidance. (6) Your state's Housing Finance Agency — local programs and resources. (7) CFPB's Home Loan Toolkit — downloadable step-by-step guide. All of these resources are free or low-cost and provide verified, unbiased information.", cat: "closing", source: "CFPB: Owning a Home", sourceUrl: "https://www.consumerfinance.gov/owning-a-home/" },
  { q: "What is the best advice for homebuyers in one sentence?", a: "Read everything before you sign it, verify everything by phone before you wire it, and get owner's title insurance before you close on it — because the only thing more expensive than doing it right is dealing with the consequences of doing it wrong.", cat: "closing" },
  { q: "How can HomeClosing101 help me?", a: "HomeClosing101 is a free educational initiative of the American Land Title Association (ALTA) designed to be your one-stop resource for the entire home closing process. On this site you'll find: interactive calculators (mortgage payments with loan type comparison, affordability, closing costs), a searchable directory of ALTA member title companies, an interactive closing checklist, 250+ frequently asked questions with verified sources, a real estate glossary with 450+ terms, printable questions to ask your title company, a document library with official CFPB forms and guides, fraud prevention resources sourced from the FBI, state insurance department contacts for all 50 states, and an AI assistant available 24/7 to answer your closing questions. Every piece of information is sourced from verified government agencies and industry authorities — nothing is fabricated.", cat: "basics", source: "HomeClosing101 by ALTA", sourceUrl: "https://homeclosing101.vercel.app/" },
];
